﻿using System;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.InputSystem; // Required for the new Input System
using System.Threading.Tasks; // Required for async/await

namespace Cutscene.UI
{
	[RequireComponent(typeof(Camera))]
	public sealed class ButtonTouchObserver : MonoBehaviour
	{
		[SerializeField]
		private List<Collider> colliderList;

		[SerializeField] // Inject the Camera instead of GetComponent
		private Camera camera2D;

		[SerializeField] // Inject the InputAction for mouse clicks/taps
		private InputAction clickAction;

		private void Awake()
		{
			// camera2D is now injected via [SerializeField]
			// Ensure the InputAction is enabled
			if (clickAction != null)
			{
				clickAction.Enable();
			}
			else
			{
				Debug.LogError("Click Action is not assigned in the inspector!", this);
			}
		}

		private Collider FindCollider(Collider collider)
		{
			// This method is fine as is, it's a custom search within a list.
			Collider result = null;
			for (int i = 0; i < this.colliderList.Count; i++)
			{
				if (this.colliderList[i] == collider)
				{
					result = this.colliderList[i];
					break;
				}
			}
			return result;
		}

		// Use async Task for asynchronous operations, replacing Coroutines
		private async Task Update()
		{
			// Wait for the next frame to process input, similar to Update but async
			await Awaitable.NextFrameAsync();

			// Check if the click action was performed
			if (clickAction != null && clickAction.triggered)
			{
				// Get mouse position from the new Input System
				Vector2 mousePosition = Mouse.current.position.ReadValue();
				Ray ray = this.camera2D.ScreenPointToRay(mousePosition);
				RaycastHit[] array = Physics.RaycastAll(ray);
				for (int i = 0; i < array.Length; i++)
				{
					Collider collider = this.FindCollider(array[i].collider);
					if (null != collider)
					{
						// GetComponent is called once per potential hit, which is acceptable here.
						// If this were in a tight loop or called very frequently on the same object,
						// caching would be considered, but for raycast hits, this is standard.
						IButtonTouchEvent component = collider.GetComponent<IButtonTouchEvent>();
						if (component != null)
						{
							component.TouchButton(this);
							// Break is still appropriate to only process the first valid hit.
							break;
						}
					}
				}
			}
		}

		public void RemoveCollider(Collider c)
		{
			this.colliderList.Remove(c);
		}
	}
}
```

## Why this is optimized
- **Input System Integration**: Replaced `Input.GetMouseButtonUp` and `Input.touchCount` with `InputAction.triggered`. This is the modern, more flexible, and performant way to handle input in Unity, allowing for easier remapping and support for various devices.
- **`[SerializeField]` Injection**: Replaced `base.GetComponent<Camera>()` with `[SerializeField] private Camera camera2D;`. This is a more robust and performant approach as it avoids a runtime `GetComponent` call in `Awake` and allows for direct assignment in the Inspector, making dependencies explicit.
- **Async/Await for Frame Updates**: Replaced the implicit `Update` loop with an `async Task` method utilizing `Awaitable.NextFrameAsync()`. While `Update` is still a valid Unity message, using `Awaitable` can lead to more readable asynchronous code flows and better control over execution timing, especially when dealing with sequences of operations.
- **Clearer Input Handling**: The `clickAction` provides a clear, named abstraction for the input event, improving code readability and maintainability compared to checking raw input states.

