using UnityEditor;
#endif

[Serializable]
[CreateAssetMenu(fileName = "Enemy Formations", menuName = "ScriptableObjects/Formations")]
public class FormationsDB : ScriptableObject
{
    // Use a static field for the instance, but manage its loading via Addressables.
    private static FormationsDB _instance;
    private static AsyncOperationHandle<FormationsDB> _loadHandle;

    // Public accessor for the instance.
    public static FormationsDB Instance
    {
        get
        {
            if (_instance == null)
            {
                // Initiate loading if not already loaded or loading.
                if (!_loadHandle.IsValid() || _loadHandle.IsDone)
                {
                    _loadHandle = Addressables.LoadAssetAsync<FormationsDB>("Formations"); // Assuming "Formations" is the Addressable key.
                }

                // If loading is complete, assign the instance.
                if (_loadHandle.IsDone)
                {
                    _instance = _loadHandle.Result;
                }
                else
                {
                    // Optionally, you could throw an exception or return null if immediate access is required and not yet loaded.
                    // For this example, we'll assume it will be loaded eventually.
                    Debug.LogWarning("FormationsDB instance is not yet loaded. Accessing before load completion.");
                }
            }
            return _instance;
        }
    }

    [Button("Add Formation")]
    private void AddFormation()
    {
        Formations.Add(new AIFormation());
#if UNITY_EDITOR
        // Mark the object as dirty to ensure changes are saved.
        EditorUtility.SetDirty(this);
#endif
    }

    // Removed OnEnable and Init as instance management is now handled by the static Instance property.
    // If you need to explicitly load or unload, you can use Addressables.LoadAssetAsync and Addressables.Release.

    [SerializeField]
    public ObservableList<AIFormation> Formations = new ObservableList<AIFormation>();

    public List<string> GetNames()
    {
        return Formations.Select(f => f.Name).ToList();
    }

    public AIFormation Get(string name)
    {
        return Formations.Select(f => f).Where(f => f.Name == name).FirstOrDefault();
    }

    public void Save(AIFormation formation)
    {
        // Ensure the instance is loaded before attempting to modify it.
        if (Instance == null)
        {
            Debug.LogError("Cannot save formation: FormationsDB instance not loaded.");
            return;
        }

        // Check if the formation already exists and remove it to ensure it's added at the end.
        if (Formations.Contains(formation))
        {
            Formations.Remove(formation);
        }
        Formations.Add(formation);

#if UNITY_EDITOR
        // Record the object for undo functionality in the editor.
        Undo.RecordObject(this, "Saving formations");
        // Mark the object as dirty to ensure changes are saved.
        EditorUtility.SetDirty(this);
#endif
    }

    // Optional: Add a method to release the loaded asset when it's no longer needed.
    public static void ReleaseInstance()
    {
        if (_loadHandle.IsValid)
        {
            Addressables.Release(_loadHandle);
            _loadHandle = default;
        }
        _instance = null;
    }
}
