using UnityEngine;
using UnityEngine.Events; // Required for UnityEvent
using System; // Required for Action

[RequireComponent(typeof(Alive))]
public class Tutorial_Attackdummy : MonoBehaviour
{
    #region Variables

    [Header("Gameobjects")]
    [SerializeField] private Transform dummyBody = null;

    // Script side
    private Alive myAlive;
    private Transform playerTransform;

    // Event for damage, using UnityEvent for better serialization and inspector integration
    [System.Serializable]
    public class DamageEvent : UnityEvent<float, GameObject> { }
    public DamageEvent onDamage;

    #endregion

    void Awake()
    {
        // Cache GetComponent in Awake for better performance
        this.myAlive = this.GetComponent<Alive>();

        // Assuming GameManager.Player.gameObject.transform is accessible and valid
        // If GameManager is also a MonoBehaviour, consider injecting it if possible
        if (GameManager.Player != null)
        {
            this.playerTransform = GameManager.Player.gameObject.transform;
        }
        else
        {
            Debug.LogError("Tutorial_Attackdummy: GameManager.Player is not set!");
        }
    }

    void Start()
    {
        // Subscribe to the onDamage event
        // Using a lambda that calls the Attacked method
        this.myAlive.onDamage += Attacked;
    }

    // Method to handle the attack logic
    private void Attacked(float dmg, GameObject dealer)
    {
        // Assuming Alive has a Heal method that takes a float
        this.myAlive.Heal(1f);

        if (this.playerTransform == null)
        {
            Debug.LogError("Tutorial_Attackdummy: Player Transform is null, cannot calculate direction.");
            return;
        }

        Vector2 dir = (this.transform.position - this.playerTransform.position).normalized;
        // Using a fixed Z rotation for simplicity, adjust if needed
        Vector3 punch = new Vector3(0, 0, -dir.x * UnityEngine.Random.Range(45f, 90f));

        this.dummyBody.Rotate(punch, Space.Self);
    }

    void Update()
    {
        // Smoothly reset rotation towards identity
        // Using Quaternion.identity for a clear target
        this.dummyBody.rotation = Quaternion.Lerp(this.dummyBody.rotation, Quaternion.identity, Time.deltaTime / 0.05f);
    }

    // Ensure the event is unsubscribed to prevent memory leaks
    void OnDestroy()
    {
        if (this.myAlive != null)
        {
            this.myAlive.onDamage -= Attacked;
        }
    }
}
```

## Why this is optimized
- **Cached `GetComponent`**: `GetComponent` calls are moved from `Start` to `Awake`. This is a minor optimization but good practice, ensuring components are ready before `Start` is called and reducing redundant calls if multiple scripts in `Awake` need the same component.
- **Event Handling**: While the original script used a lambda for the event, the `Attacked` method is now directly subscribed. This is slightly cleaner and more explicit. The `OnDestroy` method is added to properly unsubscribe from the `onDamage` event, preventing potential memory leaks if the `Tutorial_Attackdummy` object is destroyed while the `Alive` component still holds a reference.
- **Clearer Rotation Target**: `Quaternion.identity` is explicitly used as the target for `Quaternion.Lerp` in `Update`. This makes the intent of resetting the rotation to the default orientation very clear.
- **Error Handling**: Added null checks for `GameManager.Player` and `playerTransform` to prevent runtime errors if these are not properly initialized, improving script robustness.
- **Type Safety**: Explicitly using `1f` for the `Heal` method call ensures the correct overload is used if `Heal` has overloads for different numeric types.
- **Readability**: The code is slightly refactored for better readability, with clear method separation and comments explaining key parts.

