using UnityEngine;
using UnityEngine.UIElements;
using UnityEngine.Awaitable;
using System.Threading.Tasks;

namespace Cow.UI
{
    [RequireComponent(typeof(CanvasGroup))]
    public class LoadingPanel : MonoBehaviour
    {
        [SerializeField] private UIDocument uiDocument;
        [SerializeField] private string titleLabelName = "TitleLabel";
        [SerializeField] private string descriptionLabelName = "DescriptionLabel";
        [SerializeField] private string spinnerImageName = "SpinnerImage";

        private CanvasGroup canvasGroup;
        private Label titleLabel;
        private Label descriptionLabel;
        private VisualElement spinnerElement;

        private async Awaitable InitializeAwaitable { get; set; }

        private void Awake()
        {
            canvasGroup = GetComponent<CanvasGroup>();

            if (uiDocument == null)
            {
                Debug.LogError("LoadingPanel: UIDocument is not assigned.", this);
                return;
            }

            var root = uiDocument.rootVisualElement;
            titleLabel = root.Q<Label>(titleLabelName);
            descriptionLabel = root.Q<Label>(descriptionLabelName);
            spinnerElement = root.Q<VisualElement>(spinnerImageName);

            if (titleLabel == null) Debug.LogError($"LoadingPanel: Label with name '{titleLabelName}' not found.", this);
            if (descriptionLabel == null) Debug.LogError($"LoadingPanel: Label with name '{descriptionLabelName}' not found.", this);
            if (spinnerElement == null) Debug.LogError($"LoadingPanel: VisualElement with name '{spinnerImageName}' not found.", this);

            // Initialize to hidden state
            Hide();
        }

        public void SetStatus(string title, string status, bool showSpinner = false)
        {
            if (titleLabel != null) titleLabel.text = title;
            if (descriptionLabel != null) descriptionLabel.text = status;
            if (spinnerElement != null) spinnerElement.style.display = showSpinner ?DisplayStyle.Flex : DisplayStyle.None;

            canvasGroup.alpha = 1;
            canvasGroup.interactable = true;
            canvasGroup.blocksRaycasts = true;
        }

        public void Hide()
        {
            canvasGroup.alpha = 0;
            canvasGroup.interactable = false;
            canvasGroup.blocksRaycasts = false;
            if (spinnerElement != null) spinnerElement.style.display = DisplayStyle.None;
        }
    }
}
```

## Why this is optimized
- **UI Toolkit:** Replaced legacy `UnityEngine.UI.Text` and `Image` with UI Toolkit's `Label` and `VisualElement`. UI Toolkit offers better performance, a more flexible styling system (USS), and is the modern standard for UI in Unity.
- **Component Caching:** `CanvasGroup` is now cached in `Awake()` instead of being fetched every time `SetStatus` or `Hide` is called. This reduces GetComponent calls, which can be expensive, especially if done frequently.
- **Direct Element Querying:** UI Toolkit's `Query` (`Q<T>`) is used to find UI elements by name. This is more efficient and type-safe than searching through the hierarchy manually or relying on `FindObjectOfType`.
- **Clearer State Management:** The `Hide()` method now explicitly sets the spinner display to `None`, ensuring a clean state when the panel is hidden, regardless of previous settings.
- **Error Handling:** Added null checks and `Debug.LogError` for missing `UIDocument` or UI elements, making the component more robust and easier to debug during setup.

