    [SerializeField] private InputActionProperty pinchAnimationAction;
    [SerializeField] private InputActionProperty gripAnimationAction;

    [SerializeField] private Animator handAnimator;

    private void Awake()
    {
        // Input actions are typically managed by the Input System package and don't
        // require explicit GetComponent or FindObjectOfType if set up correctly in the Inspector.
        // If handAnimator was not assigned via the Inspector, you would use:
        // handAnimator = GetComponent<Animator>();
    }

    // Using Update for input polling is acceptable here as it's directly tied to frame rate.
    // For more complex asynchronous operations, Awaitable would be preferred.
    void Update()
    {
        // Read the value from the pinch action.
        // The InputSystem package handles the mapping and reading of input values.
        float triggerValue = pinchAnimationAction.action.ReadValue<float>();
        handAnimator.SetFloat("Trigger", triggerValue);

        // Read the value from the grip action.
        float gripValue = gripAnimationAction.action.ReadValue<float>();
        handAnimator.SetFloat("Grip", gripValue);
