using UnityEngine;
using UnityEngine.AddressableAssets;
using UnityEngine.ResourceManagement.AsyncOperations;
using Unity.Services.Core;
using Unity.Services.Core.Environments;
using System.Threading.Tasks; // Required for Task and async/await

public class SoundManager : MonoBehaviour
{
    private static SoundManager instance;
    public static SoundManager Instance { get { return instance; } }

    [SerializeField] private AudioSource audioSource; // Use [SerializeField] for injection

    private void Awake()
    {
        if (instance != null && instance != this)
        {
            Destroy(gameObject);
            return;
        }
        instance = this;
        DontDestroyOnLoad(gameObject);

        // Cache GetComponent in Awake
        if (audioSource == null)
        {
            audioSource = GetComponent<AudioSource>();
            if (audioSource == null)
            {
                audioSource = gameObject.AddComponent<AudioSource>();
            }
        }
        audioSource.volume = 0.5f;
    }

    #region 소리 출력
    /// <summary>
    /// 1회 출력하는 메서드
    /// </summary>
    /// <param name="assetKey"></param>
    public async Task PlaySoundOneShotAsync(string assetKey) // Use async Task for awaitable operations
    {
        AsyncOperationHandle<AudioClip> loadHandler;
        try
        {
            loadHandler = Addressables.LoadAssetAsync<AudioClip>(assetKey);
            AudioClip clip = await loadHandler.Task; // Await the task directly

            if (clip != null)
            {
                audioSource.PlayOneShot(clip);
            }
            else
            {
                Debug.LogError($"Addressable Load Failed: {assetKey} returned null.");
            }
        }
        catch (System.Exception ex)
        {
            Debug.LogError($"Addressable Load Failed: {assetKey}. Error: {ex.Message}");
        }
        finally
        {
            // Release the asset if it was loaded successfully and is no longer needed immediately
            // Note: For one-shot sounds, you might want to manage asset lifetimes carefully.
            // Releasing immediately might cause issues if the sound is played again quickly.
            // Consider a pooling mechanism or a longer release delay for frequently used sounds.
            if (loadHandler.IsValid() && loadHandler.Status == AsyncOperationStatus.Succeeded)
            {
                Addressables.Release(loadHandler);
            }
        }
    }
    #endregion
}
```

## Why this is optimized
- **`[SerializeField]` Injection**: Replaced `GetComponent` in `Awake` with `[SerializeField]` for direct assignment in the Inspector, improving initialization clarity and performance by avoiding a runtime `GetComponent` call if the field is pre-assigned.
- **`async Task` and `await`**: Replaced the `Addressables.LoadAssetAsync` callback pattern with `async Task` and `await loadHandler.Task`. This makes asynchronous code flow more linear and easier to read, manage, and debug, eliminating the need for `StartCoroutine` or manual callback handling.
- **Direct `AudioClip` Awaiting**: `await loadHandler.Task` directly waits for the `AudioClip` to be loaded, simplifying the asynchronous operation management compared to the `.Completed` event.
- **Error Handling**: Added a `try-catch-finally` block for robust error handling during asset loading and ensures `Addressables.Release` is called appropriately.
- **`Addressables.Release`**: Explicitly releasing the loaded `AudioClip` after use helps manage memory and prevent resource leaks, which is crucial for performance in larger projects.
- **`GetComponent` Caching**: `GetComponent<AudioSource>()` is now called once in `Awake` and cached, preventing repeated calls in potentially performance-sensitive methods.

