using System;
using System.Threading.Tasks;
using SNet.Core;
using SNet.Core.Events;
using Unity.Mathematics;
using UnityEngine;
using UnityEngine.Awaitable; // Required for Awaitable

[RequireComponent(typeof(Renderer))]
public class ChangeColorController : MonoBehaviour
{
    [SerializeField] private float secondsToChange = .5f;
    [SerializeField] private SNetColorEvent sNetColorEntity;
    [SerializeField] private SNetIntEvent sNetIntEvent;

    private Renderer _renderer;

    private void Awake()
    {
        _renderer = GetComponent<Renderer>();
    }

    private async void Start()
    {
        if (SNetManager.IsServer)
        {
            // Start the asynchronous color changing loop
            _ = ChangeColorAsync();
        }
    }

    private async Task ChangeColorAsync()
    {
        if (sNetColorEntity == null)
        {
            Debug.LogError("SNetColorEvent is not assigned!");
            return;
        }

        while (true)
        {
            var newColor = new Color(
                UnityEngine.Random.value,
                UnityEngine.Random.value,
                UnityEngine.Random.value
            );

            _renderer.material.color = newColor;
            sNetColorEntity.ServerBroadcast(newColor);

            // Wait for the specified duration before the next frame
            await Awaitable.NextFrameAsync(TimeSpan.FromSeconds(secondsToChange));
        }
    }

    public void ChangeColorClient(Color serverColor)
    {
        _renderer.material.color = serverColor;
        sNetIntEvent.ClientSend(UnityEngine.Random.Range(0, 10));
    }

    public void ChangeIntServer(int clientValue)
    {
        Debug.Log($"Received {clientValue} from client");
    }
}
```

## Why this is optimized
- **`Awaitable.NextFrameAsync` replaces `WaitForSeconds` and `StartCoroutine`**: This modern approach simplifies asynchronous operations, making the code more readable and easier to manage, especially for time-based delays within loops. It integrates seamlessly with `async`/`await` patterns.
- **Component Caching in `Awake`**: Caching the `Renderer` component in `Awake` instead of `Start` or on demand in `Update` (or in this case, the loop) prevents repeated `GetComponent` calls, which can be a performance bottleneck, especially if called frequently.
- **`async void` for `Start`**: While generally discouraged, `async void` is acceptable for top-level entry points like `Start` when you intend to fire-and-forget an asynchronous operation, as done here with `_ = ChangeColorAsync();`. This avoids blocking the main thread.
- **Explicit Null Check for Network Event**: Added a more robust check for `sNetColorEntity` to prevent potential `NullReferenceException` errors and provide immediate feedback if the event is not assigned.
- **Random.value for Color**: Using `UnityEngine.Random.value` directly for each color component (R, G, B) is a common and efficient way to generate random colors. `Random.ColorHSV()` is also valid but this approach is more explicit for RGB.

