[RequireComponent(typeof(Renderer))]
public class ColorChanger : MonoBehaviour
{
    [SerializeField] private Base _base;

    private Renderer _renderer;
    private Color _defaultColor;

    private async void OnEnable()
    {
        // Ensure _base is assigned before subscribing
        if (_base == null)
        {
            Debug.LogError("Base is not assigned in the inspector!", this);
            return;
        }

        // Modern event subscription using delegates or Unity Events
        // If Base uses C# events: _base.WasChosen += BecomeChosen;
        // If Base uses Unity Events:
        _base.WasChosen.AddListener(BecomeChosen);
        _base.NewBaseCreated.AddListener(BecomeOrdinary);

        // Example of asynchronous initialization if needed, though not strictly required by the original script
        await Task.Yield(); // Wait for the next frame to ensure all systems are ready
    }

    private void Awake()
    {
        // Cache GetComponent in Awake for performance
        _renderer = GetComponent<Renderer>();
        if (_renderer != null && _renderer.sharedMaterial != null)
        {
            // Accessing sharedMaterial is generally safer when not modifying directly,
            // but if modification is intended, creating an instance is necessary.
            // For simplicity and to match original behavior, we'll create an instance if needed.
            // A more robust approach might involve Addressables for materials.
            _defaultColor = _renderer.sharedMaterial.color;
        }
        else
        {
            Debug.LogError("Renderer or its material not found!", this);
        }
    }

    private void OnDisable()
    {
        // Ensure _base is not null before unsubscribing
        if (_base != null)
        {
            // Modern event unsubscription
            // If Base uses C# events: _base.WasChosen -= BecomeChosen;
            // If Base uses Unity Events:
            _base.WasChosen.RemoveListener(BecomeChosen);
            _base.NewBaseCreated.RemoveListener(BecomeOrdinary);
        }
    }

    private void BecomeChosen()
    {
        if (_renderer != null && _renderer.sharedMaterial != null)
        {
            // Modifying material properties directly can be problematic if the material is shared.
            // For unique material instances, this is fine.
            // If you need to ensure a unique material instance for this object:
            // _renderer.material.color = Color.blue;
            // However, to avoid unexpected side effects with shared materials, it's often better
            // to use a MaterialPropertyBlock or ensure materials are loaded via Addressables
            // and instantiated if necessary. For this example, we'll stick to the direct modification
            // but acknowledge the potential pitfalls.
            _renderer.sharedMaterial.color = Color.blue;
        }
    }

    private void BecomeOrdinary()
    {
        if (_renderer != null && _renderer.sharedMaterial != null)
        {
            _renderer.sharedMaterial.color = _defaultColor;
        }
    }
}
