using System.Collections.Generic;
using UnityEngine;

[CreateAssetMenu(fileName = "New Exp Data Settings", menuName = "Game Data/Experience Data")]
public class ExpData : ScriptableObject
{
    [SerializeField] private int firstLevelReq = 10;
    [SerializeField] private float exponantialFactor = .2f;
    [SerializeField] private int maxLevel = 100;
    [SerializeField] private List<int> xpPerLevel = new List<int>(); // Initialize list to prevent null reference

    /// <summary>
    /// Calculates and populates the XP requirements for each level up to maxLevel.
    /// This method can be triggered from the Inspector via a context menu.
    /// </summary>
    [ContextMenu("Set Levels")]
    private void SetLevels()
    {
        if (xpPerLevel == null)
        {
            xpPerLevel = new List<int>();
        }
        xpPerLevel.Clear();

        if (maxLevel <= 0)
        {
            Debug.LogWarning("Max Level must be greater than 0.");
            return;
        }

        xpPerLevel.Add(firstLevelReq); // XP for level 1

        for (int i = 1; i < maxLevel; i++) // Calculate XP for levels 2 to maxLevel
        {
            // Calculate next level's XP requirement based on the previous level
            int xp = Mathf.CeilToInt(xpPerLevel[i - 1] + (xpPerLevel[i - 1] * exponantialFactor));
            xpPerLevel.Add(xp);
        }

        Debug.Log($"XP requirements for {xpPerLevel.Count} levels calculated.");
    }

    /// <summary>
    /// Retrieves the XP required to reach the next level from the currentLevel.
    /// </summary>
    /// <param name="currentLevel">The player's current level (0-indexed for array access, but conceptually 1-indexed for player level).</param>
    /// <returns>The XP required for the next level, or 0 if the level is out of bounds.</returns>
    public int GetNextLevelXP(int currentLevel)
    {
        // currentLevel 0 means player is level 1, needs xpPerLevel[0] to reach level 2.
        // currentLevel 1 means player is level 2, needs xpPerLevel[1] to reach level 3.
        // So, to get XP for next level, we need xpPerLevel[currentLevel].

        if (currentLevel < 0 || currentLevel >= xpPerLevel.Count)
        {
            Debug.LogWarning($"Attempted to get XP for invalid level {currentLevel}. Max level is {xpPerLevel.Count}. Returning 0.");
            return 0;
        }
        return xpPerLevel[currentLevel];
    }

    /// <summary>
    /// Returns the maximum level defined by this data.
    /// </summary>
    public int MaxLevel => maxLevel;

    /// <summary>
    /// Returns the total number of XP requirements stored.
    /// </summary>
    public int LevelsCount => xpPerLevel.Count;
}
