using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Rendering; // For CommandBuffer if needed, though not strictly for this script

#if UNITY_EDITOR
using UnityEditor;
#endif

/// <summary>
/// WARNING: `UWP, HDRPは非対応
/// </summary>
[RequireComponent(typeof(Renderer))]
public class ZInverseMirror : MonoBehaviour
{
    [SerializeField]
    [Tooltip("positionをミラーの位置、forwardをミラーの反射方向とするTransform")]
    private Transform mirror;

    [SerializeField]
    [Tooltip("鏡用カメラのカリングマスク")]
    private LayerMask cullingMask;

    private Camera _mirrorCamera;
    private Camera _mainCamera; // Cached reference to the main camera

    private Material _rendererMaterial;

    private RenderTexture _renderTexture = null;

    private readonly Matrix4x4 _zReverseMatrix = Matrix4x4.Scale(new Vector3(1, 1, -1));

    private void Awake()
    {
        // Cache the main camera reference once
        _mainCamera = Camera.main;
        if (_mainCamera == null)
        {
            Debug.LogError("ZInverseMirror: Main Camera not found. Ensure a camera is tagged 'MainCamera'.");
            enabled = false; // Disable script if no main camera
            return;
        }

        _mirrorCamera = CreateCamera();

        // 単一マテリアルのみ対象
        _rendererMaterial = GetComponent<Renderer>().sharedMaterial;
    }

    void OnWillRenderObject()
    {
        var currentCamera = Camera.current;
        if (currentCamera == null || currentCamera == _mirrorCamera) {
            return;
        }

#if UNITY_EDITOR
        if (currentCamera == SceneView.lastActiveSceneView.camera) {
            return;
        }
#endif

        if (_renderTexture == null) {
            _renderTexture = CreateMirrorTexture();
            _mirrorCamera.targetTexture = _renderTexture;

            // targetTextureを設定するとprojectionMatrixが更新されてしまうため、
            // 対象のカメラのもので上書き
            _mirrorCamera.projectionMatrix = currentCamera.projectionMatrix;

            // 影の描画に使用されるため対象のカメラに合わせる
            _mirrorCamera.fieldOfView = currentCamera.fieldOfView;
            _mirrorCamera.aspect = currentCamera.aspect;
        }

        _mirrorCamera.worldToCameraMatrix = CalculateMirrorViewMatrix(currentCamera);
        _rendererMaterial.mainTexture = _renderTexture;

        bool oldCulling = GL.invertCulling;
        GL.invertCulling = true;
        _mirrorCamera.Render();
        GL.invertCulling = oldCulling;
    }

    private void OnBecameInvisible()
    {
        if (_renderTexture == null) {
            return;
        }

        _rendererMaterial.mainTexture = null;
        _mirrorCamera.targetTexture = null;
        ReleaseMirrorTexture(_renderTexture);

        _renderTexture = null;
    } 

    private Camera CreateCamera()
    {
        var cameraObj = new GameObject("Mirror Camera", typeof(Camera));

        // Cameraの親オブジェクトのスケールで影がおかしくなるため、親を設定しない
        // cameraObj.transform.parent = this.transform;

        var camera = cameraObj.GetComponent<Camera>();
        camera.enabled = false;
        camera.cullingMask = cullingMask;

        return camera;
    }

    private Matrix4x4 CalculateMirrorViewMatrix(Camera camera)
    {
        var mirrorMatrix =
            mirror.localToWorldMatrix *
            _zReverseMatrix *
            mirror.worldToLocalMatrix;

        return camera.worldToCameraMatrix * mirrorMatrix;
    }

    private RenderTexture CreateMirrorTexture()
    {
        // Use the cached main camera
        return RenderTexture.GetTemporary(
            width: _mainCamera.pixelWidth,
            height: _mainCamera.pixelHeight);
    }

    private void ReleaseMirrorTexture(RenderTexture texture)
    {
        RenderTexture.ReleaseTemporary(texture);
    }

    private void OnDestroy()
    {
        // Clean up the created mirror camera and render texture if still active
        if (_mirrorCamera != null)
        {
            Destroy(_mirrorCamera.gameObject);
        }
        if (_renderTexture != null)
        {
            ReleaseMirrorTexture(_renderTexture);
            _renderTexture = null;
        }
    }
}
```

## Why this is optimized
*   **`Camera.main` Caching**: The `Camera.main` property involves a lookup operation, which can be inefficient if called repeatedly (e.g., in `Update` or `OnWillRenderObject`). By caching `_mainCamera` in `Awake()`, we perform this lookup only once, significantly improving performance, especially in scenarios where `CreateMirrorTexture` might be called multiple times or if the script were to evolve to use `_mainCamera` more frequently.
*   **`[SerializeField]` for Editor Injection**: Using `[SerializeField]` for `mirror` and `cullingMask` allows developers to assign these references directly in the Unity Editor. This is the modern and recommended approach for establishing dependencies, as it's less error-prone and more performant than runtime lookups like `FindObjectOfType`.
*   **Efficient Render Texture Management**: The script correctly uses `RenderTexture.GetTemporary()` and `RenderTexture.ReleaseTemporary()`. This pattern is crucial for performance, as it allows Unity to reuse render texture memory, avoiding costly allocations and deallocations, especially when the mirror might go in and out of view.
*   **`RequireComponent` for Dependency Enforcement**: The `[RequireComponent(typeof(Renderer))]` attribute ensures that any GameObject with this script automatically has a `Renderer` component. This prevents runtime errors and makes the script's dependencies explicit, improving maintainability.
*   **Explicit Cleanup in `OnDestroy`**: Adding an `OnDestroy` method to explicitly clean up the dynamically created `_mirrorCamera` GameObject and release the `_renderTexture` ensures that no memory leaks or orphaned GameObjects persist when the mirror object is destroyed, promoting better resource management.

