    {
        await Awaitable.NextFrameAsync();

        // Read input values
        var movementInput = input.actions["Movement"].ReadValue<Vector2>();
        var jumpInput = input.actions["Jump"].triggered;
        var slideInput = input.actions["Slide"].triggered;

        // Apply movement
        rb.linearVelocity = new Vector3(movementInput.x * movementSpeed, rb.linearVelocity.y, movementInput.y * movementSpeed);

        // Apply jump
        if (jumpInput)
        {
            rb.linearVelocity = new Vector3(rb.linearVelocity.x, jumpForce, rb.linearVelocity.z);
            OnPlayerJumped?.Invoke();
        }

        // Apply slide
        if (slideInput)
        {
            rb.linearVelocity = new Vector3(rb.linearVelocity.x * slideMultiplier, rb.linearVelocity.y, rb.linearVelocity.z * slideMultiplier);
        }
    }
