            await Awaitable.NextFrameAsync();
        }

        // Turn off laser
        if (isLaserOn && activeTimer >= laserOnDuration)
        {
            isLaserOn = false;
            await Awaitable.NextFrameAsync();
        }

        activeTimer += Time.deltaTime;
        await Awaitable.NextFrameAsync();
    }
