[RequireComponent(typeof(Camera))]
public class CameraZoom : MonoBehaviour
{
    [SerializeField] private float zoomStep = 50f;
    [SerializeField] public float minZoom = 10f;
    [SerializeField] public float maxZoom = 60f;
    [SerializeField] private float zoomSmoothSpeed = 100f;

    private Camera mainCamera;
    private float currentZoom;
    private float targetZoom;

    private InputAction zoomIn;
    private InputAction zoomOut;

    private async void Awake()
    {
        mainCamera = GetComponent<Camera>();
        zoomIn = new InputAction("ZoomIn", binding: "<Mouse>/scroll/y");
        zoomOut = new InputAction("ZoomOut", binding: "<Mouse>/scroll/y");

        zoomIn.triggered += OnZoomIn;
        zoomOut.triggered += OnZoomOut;
    }

    private void OnZoomIn(InputAction.CallbackContext context)
    {
        if (context.phase == InputActionPhase.Performed && context.ReadValue<float>() > 0)
        {
            ZoomIn();
        }
    }

    private void OnZoomOut(InputAction.CallbackContext context)
    {
        if (context.phase == InputActionPhase.Performed && context.ReadValue<float>() < 0)
        {
            ZoomOut();
        }
    }

    private async void ZoomIn()
    {
        targetZoom = Mathf.Min(targetZoom + zoomStep, maxZoom);
        await SmoothZoom();
    }

    private async void ZoomOut()
    {
        targetZoom = Mathf.Max(targetZoom - zoomStep, minZoom);
        await SmoothZoom();
    }

    private async Task SmoothZoom()
    {
        while (Mathf.Abs(mainCamera.fieldOfView - targetZoom) > 0.1f)
        {
            mainCamera.fieldOfView = Mathf.MoveTowards(mainCamera.fieldOfView, targetZoom, zoomSmoothSpeed * Time.deltaTime);
            await Awaitable.NextFrameAsync();
        }
    }
}
