    [SerializeField] float m_DamagePoints;

    [SerializeField] Rigidbody m_Rigidbody;
    [SerializeField] Transform m_Transform;

    private Camera camera;

    private void Awake()
    {
        m_Rigidbody = GetComponent<Rigidbody>();
        m_Transform = transform;
        camera = Camera.main;
    }

    public async void Shoot(Vector3 targetPos, float travelDuration)
    {
        await BallisticMoveAsync(travelDuration, m_Transform.position, targetPos);
        Destroy(gameObject);
    }

    private async Task BallisticMoveAsync(float travelTime, Vector3 startPos, Vector3 endPos)
    {
        float sqrTravelTime = travelTime * travelTime;
        float elapsedTime = 0;

        while (elapsedTime < travelTime)
        {
            float t = elapsedTime / travelTime;
            m_Transform.position = Vector3.Lerp(startPos, endPos, t);
            elapsedTime += Time.fixedDeltaTime;
            await Awaitable.NextFrameAsync();
        }
    }
}
