        rigidbody = GetComponent<Rigidbody>();
        mainCamera = Camera.main;
        controls = new PlayerControls();
        controls.Gameplay.Movement.performed += ctx => Move(ctx.ReadValue<Vector2>());
        controls.Gameplay.Jump.performed += ctx => Jump();
        controls.Gameplay.Crouch.performed += ctx => Crouch();
    }

    private void OnEnable()
    {
        controls.Gameplay.Enable();
    }

    private void OnDisable()
    {
        controls.Gameplay.Disable();
    }

    private async void Move(Vector2 direction)
    {
        // Apply movement
        rigidbody.linearVelocity = new Vector3(direction.x * speed, rigidbody.linearVelocity.y, direction.y * speed);
        await Awaitable.NextFrameAsync();
    }

    private async void Jump()
    {
        // Apply jump force
        if (isGrounded)
        {
            rigidbody.linearVelocity = new Vector3(rigidbody.linearVelocity.x, jumpForce, rigidbody.linearVelocity.z);
            isGrounded = false;
            jumpCount++;
        }
        else if (jumpCount < maxJumps)
        {
            rigidbody.linearVelocity = new Vector3(rigidbody.linearVelocity.x, jumpForce, rigidbody.linearVelocity.z);
            jumpCount++;
        }
        await Awaitable.NextFrameAsync();
    }

    private async void Crouch()
    {
        // Apply crouch speed
        if (isCrouching)
        {
            isCrouching = false;
            speed = originalSpeed;
        }
        else
        {
            isCrouching = true;
            originalSpeed = speed;
            speed = crouchSpeed;
        }
        await Awaitable.NextFrameAsync();
    }

    private async void CheckGround()
    {
        // Check if player is grounded
        isGrounded = false;
        Collider[] hitColliders = Physics.OverlapSphere(transform.position, 0.1f);
        foreach (var hitCollider in hitColliders)
        {
            if (hitCollider.gameObject != gameObject)
            {
                isGrounded = true;
                break;
            }
        }
        await Awaitable.NextFrameAsync();
    }

    private async void Update()
    {
        await CheckGround();
    }
