        bulletPrefab = await Addressables.LoadAssetAsync<GameObject>("BulletPrefab").Task;
        shootSound = await Addressables.LoadAssetAsync<AudioClip>("ShootSound").Task;
        boombSound = await Addressables.LoadAssetAsync<AudioClip>("BoombSound").Task;
        dieSound = await Addressables.LoadAssetAsync<AudioClip>("DieSound").Task;
    }

    private async void Update()
    {
        // Update shooting behavior
        if (canShoot)
        {
            delayCounter -= Time.deltaTime;
            if (delayCounter <= 0f)
            {
                // Shoot
                GameObject bullet = Instantiate(bulletPrefab, firePoint.position, firePoint.rotation);
                Rigidbody bulletRb = bullet.GetComponent<Rigidbody>();
                bulletRb.linearVelocity = firePoint.forward * speed;

                // Play shoot sound
                AudioSource.PlayClipAtPoint(shootSound, mainCamera.transform.position);

                delayCounter = shootDelay;
            }
        }

        // Update boomb behavior
        delayBoomb -= Time.deltaTime;
        if (delayBoomb <= 0f)
        {
            // Boomb
            GameObject boomb = Instantiate(boombPrefab, firePoint.position, firePoint.rotation);
            Rigidbody boombRb = boomb.GetComponent<Rigidbody>();
            boombRb.linearVelocity = firePoint.forward * speed;

            // Play boomb sound
            AudioSource.PlayClipAtPoint(boombSound, mainCamera.transform.position);

            delayBoomb = delaySpeed;
        }

        await Awaitable.NextFrameAsync();
    }

