using System.Collections;
using UnityEngine;
using UnityEngine.Addressables;
using UnityEngine.InputSystem;

public class FinalCameraTrigger : MonoBehaviour
{
    [SerializeField] private Transform orbo;
    [SerializeField] private CameraController cameraController;
    [SerializeField] private DialogueController dialogueController;
    [SerializeField] private MonoBehaviour orboMovementScript;
    [SerializeField] private Vector3 finalCameraPosition = new Vector3(-11.98f, 5f, -13.28f);
    [SerializeField] private Vector3 finalCameraRotation = new Vector3(1f, 0f, 0f);
    [SerializeField] private float transitionDuration = 3f;

    private bool triggered = false;
    private Rigidbody orboRb;

    private async void Awake()
    {
        orboRb = orbo.GetComponent<Rigidbody>();
    }

    private async void OnTriggerEnter(Collider other)
    {
        if (triggered || other.transform != orbo) return;

        triggered = true;

        // Lock movement
        if (orboMovementScript != null)
            orboMovementScript.enabled = false;

        // Lock physics
        orboRb.linearVelocity = Vector3.zero;
        orboRb.angularVelocity = Vector3.zero;

        // Transition camera
        float elapsedTime = 0f;
        Vector3 initialCameraPosition = cameraController.transform.position;
        Quaternion initialCameraRotation = cameraController.transform.rotation;

        while (elapsedTime < transitionDuration)
        {
            cameraController.transform.position = Vector3.Lerp(initialCameraPosition, finalCameraPosition, elapsedTime / transitionDuration);
            cameraController.transform.rotation = Quaternion.Slerp(initialCameraRotation, Quaternion.Euler(finalCameraRotation), elapsedTime / transitionDuration);

            elapsedTime += Time.deltaTime;
