    [SerializeField] private float playerSpeed = 2.0f;
    [SerializeField] private float jumpHeight = 1.0f;
    [SerializeField] private float gravityValue = -9.81f;

    private CharacterController controller;
    private PhotonView pv;
    private Vector3 playerVelocity;
    private bool groundedPlayer;
    private Transform cameraTransform;
    private PlayerControls controls;

    private void Awake()
    {
        controller = GetComponent<CharacterController>();
        pv = GetComponent<PhotonView>();
        cameraTransform = Camera.main.transform;
        controls = new PlayerControls();

        controls.Gameplay.Jump.performed += ctx => Jump();
    }

    private async void Start()
    {
        await controls.Gameplay.EnableAsync();

        if (!pv.IsMine)
        {
            Destroy(GetComponentInChildren<CinemachineVirtualCamera>().gameObject);
            Destroy(GetComponentInChildren<CharacterController>());
        }
    }

    private void Update()
    {
        if (pv.IsMine)
        {
            Vector2 input = controls.Gameplay.Movement.ReadValue<Vector2>();
            playerVelocity.x = input.x * playerSpeed;
            playerVelocity.z = input.y * playerSpeed;

            if (groundedPlayer && controls.Gameplay.Jump.triggered)
            {
                playerVelocity.y += Mathf.Sqrt(jumpHeight * -3.0f * gravityValue);
            }

            playerVelocity.y += gravityValue * Time.deltaTime;

            controller.Move(playerVelocity * Time.deltaTime);
        }
    }

    private void Jump()
    {
        if (groundedPlayer)
        {
            playerVelocity.y = Mathf.Sqrt(jumpHeight * -3.0f * gravityValue);
        }
    }

    private void OnCollisionEnter(Collision collision)
    {
        if (collision.gameObject.CompareTag("Ground"))
        {
            groundedPlayer = true;
        }
    }

    private void OnCollisionExit(Collision collision)
    {
        if (collision.gameObject.CompareTag("Ground"))
        {
            groundedPlayer = false;
        }
    }
}
