    public class PhysicsPoolable : Poolable
    {
        [SerializeField]
        private bool resetPhysicsOnSpawn = true;

        [SerializeField]
        private bool enableSleepTimerRecycle = false;

        [SerializeField]
        private float sleepRecycleTime = 3f;

        [SerializeField]
        private bool enableCollisionRecycle = false;

        private AsyncOperationHandle<GameObject> asyncHandle;

        public async void Spawn()
        {
            if (resetPhysicsOnSpawn)
            {
                // Reset physics state
                await ResetPhysicsAsync();
            }

            if (enableSleepTimerRecycle)
            {
                // Start sleep timer
                await StartSleepTimerAsync();
            }
        }

        private async Task ResetPhysicsAsync()
        {
            // Reset physics state using Addressables
            asyncHandle = Addressables.LoadAssetAsync<GameObject>("PhysicsReset");
            await asyncHandle.Task;
        }

        private async Task StartSleepTimerAsync()
        {
            // Start sleep timer using async/await
            await Awaitable.NextFrameAsync();
            await Task.Delay((int)sleepRecycleTime * 1000);
            // Recycle object after sleep timer expires
            Recycle();
        }

        private void OnCollisionEnter(Collision collision)
        {
            if (enableCollisionRecycle)
            {
                // Recycle object on collision
                Recycle();
            }
        }

        private void Recycle()
        {
            // Recycle object using Addressables
            Addressables.Release(asyncHandle);
        }
    }
