    [SerializeField, Range(1f, 20f)] private float distance = 5f;
    [SerializeField, Range(1f, 20f)] private float minDistance = 1;
    [SerializeField, Range(1f, 20f)] private float maxDistance = 1;
    [SerializeField] private Vector3 focusOffset = Vector3.zero;

    [SerializeField] private float rotationSpeed = 90f;
    [SerializeField, Range(-89f, 89f)] private float minVerticalAngle = -45f, maxVerticalAngle = 45f;

    private Camera camera;
    private InputActionMap inputActionMap;

    public void Awake() {
        camera = GetComponent<Camera>();
        inputActionMap = Addressables.LoadAssetAsync<InputActionMap>("InputMap").WaitForCompletion();
    }

    public async void LateUpdate() {
        if (focus != null) {
            var rotationInput = inputActionMap.FindAction("Rotation").ReadValue<Vector2>();
            var zoomInput = inputActionMap.FindAction("Zoom").ReadValue<float>();

            // Apply rotation and zoom
            transform.RotateAround(focus.position, Vector3.up, rotationInput.x * rotationSpeed * Time.deltaTime);
            transform.RotateAround(focus.position, transform.right, rotationInput.y * rotationSpeed * Time.deltaTime);

            distance -= zoomInput * Time.deltaTime;
            distance = Mathf.Clamp(distance, minDistance, maxDistance);

            transform.position = focus.position + focusOffset + (transform.position - focus.position).normalized * distance;
        }

        await Awaitable.NextFrameAsync();
    }
}

