using UnityEngine;
using UnityEngine.InputSystem;

public class PlayerController : MonoBehaviour
{
    // Movement speed of the monkey
    public float moveSpeed = 5f;

    // Jump force for the monkey
    public float jumpForce = 5f;

    // Reference to the Rigidbody component
    [SerializeField] private Rigidbody rb;

    // Reference to the Camera component
    [SerializeField] private Camera mainCamera;

    // Flag to check if the player is on the ground
    private bool isGrounded;

    private PlayerControls controls;

    private void Awake()
    {
        // Get the Rigidbody and Camera components
        if (!rb) rb = GetComponent<Rigidbody>();
        if (!mainCamera) mainCamera = Camera.main;

        // Initialize the Input System
        controls = new PlayerControls();
        controls.Gameplay.Movement.performed += ctx => Move(ctx.ReadValue<Vector2>());
        controls.Gameplay.Jump.performed += ctx => Jump();
    }

    private async void OnEnable()
    {
        await controls.Gameplay.EnableAsync();
    }

    private async void OnDisable()
    {
        await controls.Gameplay.DisableAsync();
    }

    private void Move(Vector2 direction)
    {
        // Get horizontal (A/D) and vertical (W/S) input
        float moveX = direction.x;
        float moveZ = direction.y;

        // Get camera forward and right directions
        Vector3 forward = mainCamera.transform.forward;
        Vector3 right = mainCamera.transform.right;

        // Calculate the movement direction
        Vector3 movement = (forward * moveZ + right * moveX).normalized;

        // Apply the movement
        rb.linearVelocity = new Vector3(movement.x * moveSpeed, rb.linearVelocity.y, movement.z * moveSpeed);
    }

    private void Jump()
    {
        // Check if the player is on the ground
        if (isGrounded)
        {
            // Apply the jump force
            rb.linearVelocity = new Vector3(rb.linearVelocity.x, jumpForce, rb.linearVelocity.z);
        }
    }
}
