    [CreateAssetMenu(fileName = "EZImageCapture", menuName = "EZUnity/EZImageCapture", order = 0)]
    public class EZImageCapture : ScriptableObject
    {
        public Vector2Int resolution = new Vector2Int(1920, 1080);
        public TextureFormat textureFormat = TextureFormat.ARGB32;
        public string filePath = "EZScreenshots";

        public void CameraCapture(Camera camera, string path)
        {
            Texture2D texture;
            if (camera.targetTexture == null)
            {
                RenderTexture tempRT = new RenderTexture(resolution.x, resolution.y, 24);
                camera.targetTexture = tempRT;
                texture = new Texture2D(resolution.x, resolution.y, textureFormat, false);
            }
            else
            {
                texture = new Texture2D(camera.targetTexture.width, camera.targetTexture.height, textureFormat, false);
            }
            camera.Render();
            RenderTexture.active = camera.targetTexture;
            texture.ReadPixels(new Rect(0, 0, camera.targetTexture.width, camera.targetTexture.height), 0, 0);
            RenderTexture.active = null;
            byte[] bytes = texture.EncodeToPNG();
            File.WriteAllBytes(path, bytes);
            if (camera.targetTexture != null && camera.targetTexture != tempRT)
            {
                camera.targetTexture = null;
            }
            if (tempRT != null)
            {
                RenderTexture.ReleaseTemporary(tempRT);
            }
        }
    }
}
