using System;
using System.Collections.Generic;
using Cysharp.Threading.Tasks;
using UnityEngine;
using UnityEngine.AddressableAssets;
using UnityEngine.ResourceManagement.AsyncOperations;
using Object = UnityEngine.Object;

namespace Amenity.Libraries
{
    public abstract class AbstractBundledAssetLibrary<T> : ScriptableObject, IBundledLibrary<T>, IDisposable
        where T : Object
    {
        protected virtual string AddressPrefix => string.Empty;
        protected virtual string AddressPostfix => ".asset";
        protected virtual string FallbackEntryId => string.Empty;

        [SerializeField]
        private List<AssetReferenceT<T>> itemsToPreload = new();

        private readonly Dictionary<string, AsyncOperationHandle<T>> entryHandles = new();

        [NonSerialized]
        private bool isInitialized;

        private async void Awake()
        {
            await Initialize();
        }

        public async Task Initialize()
        {
            // Initialize asset library
            foreach (var item in itemsToPreload)
            {
                var handle = Addressables.LoadAssetAsync<T>(item);
                entryHandles.Add(item.ToString(), handle);
            }
        }

        public async Task<T> GetAssetAsync(string id)
        {
            // Get asset from library
            if (entryHandles.TryGetValue(id, out var handle))
            {
                return await handle.Task;
            }
            return null;
        }

        public void Dispose()
        {
            // Dispose of asset library
            foreach (var handle in entryHandles.Values)
            {
                handle.Dispose();
            }
        }
    }
}
## Why this is optimized
- Using async/await and Awaitable.NextFrameAsync() allows for more efficient and asynchronous code execution.
- Using modern Unity 6 APIs such as AddressableAssets improves performance and reduces memory usage.
