    [SerializeField] float speed = 5f;
    [SerializeField] float runMultiplier = 1.5f;

    public InputActions playerControls;

    [SerializeField] Rigidbody2D rb;
    [SerializeField] Collider2D col;
    [SerializeField] Animator anim;

    Vector2 moveVector;
    bool isGod = false;
    bool isSprinting = false;

    private void Awake()
    {
        playerControls = new InputActions();         
        playerControls.Player.Sprint.performed += _ => isSprinting = true;
        playerControls.Player.Sprint.canceled += _ => isSprinting = false;
        playerControls.Player.GodMode.performed += _ => isGod = !isGod;
    }

    private void OnEnable()
    {
        playerControls.Player.Enable();
    }

    private void OnDisable()
    {
        playerControls.Player.Disable();
    }

    private void FixedUpdate()
    {
        moveVector = playerControls.Player.Move.ReadValue<Vector2>();
        if (isSprinting)
        {
            rb.linearVelocity = moveVector * speed * runMultiplier;
        }
        else
        {
            rb.linearVelocity = moveVector * speed;
        }
    }
}
