using UnityEngine;
using UnityEngine.InputSystem;

[CreateAssetMenu(menuName = "Input/Input Reader", fileName = "Input Reader")]
public class InputReader : ScriptableObject
{
    public InputActionAsset asset;

    public event UnityAction<Vector2> moveEvent;

    public event UnityAction jumpEvent;
    public event UnityAction jumpCancelledEvent;


    public event UnityAction pauseEvent;
    public event UnityAction unPauseEvent;


    InputAction moveAction;
    InputAction jumpAction;
    InputAction pauseAction;
    InputAction unPauseAction;

    private void OnEnable()
    {
        moveAction = asset.FindAction("Move", true);
        jumpAction = asset.FindAction("Jump");
        pauseAction = asset.FindAction("Pause", true);
        unPauseAction = asset.FindAction("UnPause", true);

        moveAction.performed += ctx => moveEvent?.Invoke(ctx.ReadValue<Vector2>());
        jumpAction.performed += ctx => jumpEvent?.Invoke();
        jumpAction.canceled += ctx => jumpCancelledEvent?.Invoke();
        pauseAction.performed += ctx => pauseEvent?.Invoke();
        unPauseAction.performed += ctx => unPauseEvent?.Invoke();
    }

    private void OnDisable()
    {
        moveAction.performed -= ctx => moveEvent?.Invoke(ctx.ReadValue<Vector2>());
        jumpAction.performed -= ctx => jumpEvent?.Invoke();
        jumpAction.canceled -= ctx => jumpCancelledEvent?.Invoke();
