    [RequireComponent(typeof(CharacterController))]
    [RequireComponent(typeof(PlayerInput))]

    public class FirstPersonController : MonoBehaviour
    {
        [Header("Player")]
        [Tooltip("Move speed of the character in m/s")]
        public float MoveSpeed = 4.0f;
        [Tooltip("Sprint speed of the character in m/s")]
        public float SprintSpeed = 6.0f;
        [Tooltip("Rotation speed of the character")]
        public float RotationSpeed = 1.0f;
        [Tooltip("Acceleration and deceleration")]
        public float SpeedChangeRate = 10.0f;

        [Space(10)]
        [Tooltip("The height the player can jump")]
        public float JumpHeight = 1.2f;

        [SerializeField]
        private PlayerInput playerInput;

        [SerializeField]
        private CharacterController characterController;

        private Vector2 moveInput;
        private bool isSprinting;
        private bool isJumping;

        private void Awake()
        {
            characterController = GetComponent<CharacterController>();
            playerInput = GetComponent<PlayerInput>();
        }

        private async void Update()
        {
            moveInput = playerInput.actions["Move"].ReadValue<Vector2>();
            isSprinting = playerInput.actions["Sprint"].triggered;
            isJumping = playerInput.actions["Jump"].triggered;

            Vector3 movement = new Vector3(moveInput.x, 0, moveInput.y);
            movement = transform.TransformDirection(movement);

            if (isSprinting)
            {
                characterController.linearVelocity = Vector3.Lerp(characterController.linearVelocity, movement * SprintSpeed, SpeedChangeRate * Time.deltaTime);
            }
            else
            {
                characterController.linearVelocity = Vector3.Lerp(characterController.linearVelocity, movement * MoveSpeed, SpeedChangeRate * Time.deltaTime);
            }

            if (isJumping && characterController.isGrounded)
            {
                characterController.linearVelocity = new Vector3(characterController.linearVelocity.x, JumpHeight, characterController.linearVelocity.z);
            }

            await Awaitable.NextFrameAsync();
        }
    }
}
