public class PlayerMotor : MonoBehaviour, IDataPersistence
{
    [SerializeField] private CharacterController controller;
    [SerializeField] private PlayerStamina playerStamina;
    [SerializeField] private Camera mainCamera;
    private Vector3 playerVelocity;
    private Vector3 playerPosition;
    private bool isGrounded;

    public float speed = 5f;
    public float gravity = -9.8f;
    public float jumpHeight = 3f;
    public float RegenRate = 0.5f;
    public bool canMove = true;
    [SerializeField] public float stamina;
    [SerializeField] public float maxStamina;
    [SerializeField] private bool sprinting = false;

    bool crouching = false;
    float crouchTimer = 1;
    bool lerpCrouch = false;
    private bool newGame = true;

    private async void Start()
    {
        await Addressables.LoadAssetAsync<PlayerStamina>("PlayerStamina").Task;
        mainCamera = await Addressables.LoadAssetAsync<Camera>("MainCamera").Task;
    }

    private async void Update()
    {
        var moveInput = GameControls.Instance.Player.Move.ReadValue<Vector2>();
        var sprintInput = GameControls.Instance.Player.Sprint.triggered;
        var crouchInput = GameControls.Instance.Player.Crouch.triggered;

        if (canMove)
        {
            playerVelocity.x = moveInput.x * speed;
            playerVelocity.z = moveInput.y * speed;

            if (sprintInput && stamina > 0)
            {
                sprinting = true;
                playerVelocity *= 1.5f;
            }
            else
            {
                sprinting = false;
            }

            if (crouchInput)
            {
                crouching = true;
            }
            else
            {
                crouching = false;
            }

            if (crouching)
            {
                playerVelocity.y -= gravity * Time.deltaTime;
            }
            else
            {
                playerVelocity.y -= gravity * Time.deltaTime;
                if (isGrounded && GameControls.Instance.Player.Jump.triggered)
                {
                    playerVelocity.y = Mathf.Sqrt(jumpHeight * -3 * gravity);
                }
            }

            controller.Move(playerVelocity * Time.deltaTime);
        }

        await Awaitable.NextFrameAsync();
    }

    private async void FixedUpdate()
    {
        isGrounded = controller.isGrounded;

        if (isGrounded && playerVelocity.y < 0)
        {
            playerVelocity.y = 0f;
        }

        await Awaitable.NextFrameAsync();
    }

