using UnityEngine;
using Unity.Jobs;
using Unity.Burst;
using Unity.Collections;
using Unity.Mathematics;

[RequireComponent(typeof(MeshFilter)), RequireComponent(typeof(MeshCollider))]
public class Chunk : MonoBehaviour
{
    [SerializeField] private int size;
    [SerializeField] private float amplitude;
    [SerializeField] private float frequency;
    [SerializeField] private float3 position;
    [SerializeField] private float threshold;

    private MeshFilter meshFilter;
    private MeshCollider meshCollider;

    private void Awake()
    {
        meshFilter = GetComponent<MeshFilter>();
        meshCollider = GetComponent<MeshCollider>();
    }

    public async void GenerateChunk()
    {
        var chunkJob = new ChunkJob
        {
            size = size,
            amplitude = amplitude,
            frequency = frequency,
            position = position,
            threshold = threshold
        };

        var handle = chunkJob.Schedule(size * size * size, 1);
        await Awaitable.NextFrameAsync();
        handle.Complete();

        // Create mesh and collider
        var mesh = new Mesh();
        mesh.SetVertices(chunkJob.vertices);
        mesh.SetTriangles(chunkJob.triangles, 0);
        meshFilter.mesh = mesh;
        meshCollider.sharedMesh = mesh;
    }

    [BurstCompile]
    public struct ChunkJob : IJobParallelFor
    {
        // The size of the chunk.
        [ReadOnly]
        public int size;

        // The amplitude of the noise.
        [ReadOnly]
        public float amplitude;

        // The frequency of the noise.
        [ReadOnly]
        public float frequency;

        // The noise position.
        [ReadOnly]
        public float3 position;

        // Noise threshold
        [ReadOnly]
        public float threshold;

        public NativeArray<Vector3> vertices;
        public NativeArray<int> triangles;

        public void Execute(int index)
        {
            // Calculate noise and generate cube
            var noise = math.sin((index / (float)size) * frequency) * amplitude;
            if (noise > threshold)
            {
                // Generate cube
                var cubeIndex = index % (size * size);
                var cubeX = cubeIndex % size;
                var cubeY = (cubeIndex / size) % size;
                var cubeZ = index / (size * size);

                vertices[index] = new Vector3(cubeX, cubeY, cubeZ);
                triangles[index] = index;
            }
        }
    }
}
