    private ECSManager manager;
    private InputAction rewindAction;

    protected override void OnCreate()
    {
        base.OnCreate();
        manager = World.GetOrCreateSystem<ECSManager>();
        rewindAction = new InputAction("Rewind", binding: "<Keyboard>/r");
    }

    protected override void OnUpdate()
    {
        if (rewindAction.triggered)
        {
            Entities.ForEach((ref IsRewindComponent isRewindComponent) =>
            {
                if (isRewindComponent.RewindDuration == 3f)
                {
                    List<SystemBase> allSystems = World.GetSystems(SystemBase.SystemType.Normal).ToList();

                    foreach (var system in allSystems)
                    {
                        if ((system.GetType().Name != "RewindSystem") && (system.GetType().Name != "InputSystem"))
                        {
                            manager.Config.SystemsEnabled[system.GetType().Name] = false;
                        }
                    }
                }
            });
        }
    }
}

