        Debug.Log($"[StickyGoo] Init → lifeTime = {lifeTime:F1}s", this);
    }

    private void Awake()
    {
        Collider col = GetComponent<Collider>();
        if (!col.isTrigger)
            Debug.LogWarning("[StickyGoo] Collider is NOT a trigger!", this);
    }

    private void Start()
    {
        if (!lifeSet) lifeTime = defaultLifeTime;
        Destroy(gameObject, lifeTime);
    }

    private void OnTriggerEnter(Collider other)
    {
        // Slow down the object that entered the trigger
        other.attachedRigidbody.linearVelocity *= slowMultiplier;
        Invoke(nameof(ResetSpeed), slowDuration);
    }

    private void ResetSpeed()
