    [DisallowMultipleComponent]
    public class MouseHoverAuthoring : MonoBehaviour
    {
        public GameObject HoverPrefab;
        public bool IgnoreTriggers;

        private Entity previousEntity;
        private Entity currentEntity;
        private Entity hoverEntity;

        private void Awake()
        {
            previousEntity = Entity.Null;
            currentEntity = Entity.Null;
            hoverEntity = Entity.Null;
        }

        private void Update()
        {
            // Raycast from mouse position
            Ray ray = Camera.main.ScreenPointToRay(Input.mousePosition);
            if (Physics.Raycast(ray, out RaycastHit hit))
            {
                Entity entity = hit.transform.GetComponent<Entity>().Entity;
                if (entity != previousEntity)
                {
                    previousEntity = currentEntity;
                    currentEntity = entity;
                    hoverEntity = entity;
                }
            }
            else
            {
                previousEntity = currentEntity;
                currentEntity = Entity.Null;
                hoverEntity = Entity.Null;
            }
        }
    }
}
