using System.Collections;
using System.Threading;
using UnityEngine;
using UnityEngine.UI;
using UnityEngine.Addressables;

namespace UnityEngine.XR.ARFoundation.Samples
{
    public class FadeAfterDuration : MonoBehaviour
    {
        [SerializeField]
        List<Graphic> graphicsToFade = new();

        [SerializeField, Min(0)]
        float secondsBeforeFade = 5;

        [SerializeField, Min(0.001f)]
        float secondsToFade = 2;

        List<Color> startColors = new();
        float fadeBeginTime;

        [SerializeField]
        UnityEvent fadeComplete = new();
        public UnityEvent FadeComplete => fadeComplete;

        private Camera cameraCache;

        private async Awaitable Start()
        {
            cameraCache = GameObject.FindObjectOfType<Camera>();
            await Awaitable.NextFrameAsync();
            foreach (var graphic in graphicsToFade)
            {
                startColors.Add(graphic.color);
            }
            fadeBeginTime = Time.time;
        }

        private async Awaitable Update()
        {
            if (Time.time - fadeBeginTime >= secondsBeforeFade)
            {
                float fadeProgress = (Time.time - fadeBeginTime - secondsBeforeFade) / secondsToFade;
                foreach (var graphic in graphicsToFade)
                {
                    graphic.color = new Color(startColors[graphicsToFade.IndexOf(graphic)].r, startColors[graphicsToFade.IndexOf(graphic)].g, startColors[graphicsToFade.IndexOf(graphic)].b, 1 - fadeProgress);
                }
                if (fadeProgress >= 1)
                {
                    fadeComplete.Invoke();
                }
                await Awaitable.NextFrameAsync();
            }
        }

        public void ResetFade()
        {
            fadeBeginTime = Time.time;
        }
    }
}
