        #region Fields
        [ReadOnly][SerializeField] NavGrid _grid;
        [ReadOnly][SerializeField] int _currentNodeIndex;
        int _previousNodeIndex = -1;
        [Tooltip("world units per second")]
        [SerializeField] float _speed = 1;
        [Tooltip("movement speed is multiplied by it. Default should be 1")]
        [SerializeField] float _speedModifier = 1;
        [Tooltip("Inverse of time needed to reach target rotation. 1 means it takes 1 second to reach new rotation.")]
        [SerializeField] float _rotationSpeed = 4;
        bool _cancelFlag = false;
        [SerializeField] private PlayerControls _playerControls;
        private Rigidbody _rb;
        private Camera _mainCamera;

        private async void Start()
        {
            _rb = GetComponent<Rigidbody>();
            _mainCamera = Camera.main;
            _playerControls = new PlayerControls();
            _playerControls.Gameplay.Movement.performed += ctx => Move(ctx.ReadValue<Vector2>());
            _playerControls.Gameplay.Movement.canceled += ctx => CancelMovement();
            await _playerControls.Gameplay.Movement.EnableAsync();
        }

        private void Move(Vector2 direction)
        {
            // Calculate movement direction
            Vector3 movementDirection = new Vector3(direction.x, 0, direction.y);
            // Apply movement
            _rb.linearVelocity = movementDirection * _speed * _speedModifier;
        }

        private void CancelMovement()
        {
            _cancelFlag = true;
            _rb.linearVelocity = Vector3.zero;
        }

        private async void Update()
        {
            // Update rotation
            float rotation = _rotationSpeed * Time.deltaTime;
            transform.Rotate(0, rotation, 0);
            await Awaitable.NextFrameAsync();
        }
    }
}
