using UnityEngine.EventSystems;
using UnityEngine.InputSystem;
using UnityEventKit;

public class UnitSelectionManager : MonoBehaviour
{
    [SerializeField] private Vector2EventChannelSO _onSelectionBoxStarted;
    [SerializeField] private Vector2EventChannelSO _onSelectionBoxEnded;
    [SerializeField] private BoolEventChannelSO _onBarracksSelected;

    private PlayerInputActions _playerInputActions;

    private InputAction _onLeftButtonPressed;
    private InputAction _onLeftButtonReleased;

    private EntityManager _entityManager;

    private static Vector2 _selectionStartPosition;
    private Vector2 _selectionEndPosition;

    private readonly float _minSelectionBoxSize = 80;

    private void Awake()
    {
        _entityManager = World.DefaultGameObjectInjectionWorld.EntityManager;
        _playerInputActions = new PlayerInputActions();
        _onLeftButtonPressed = _playerInputActions.FindAction("LeftButtonPressed");
        _onLeftButtonReleased = _playerInputActions.FindAction("LeftButtonReleased");
        _onLeftButtonPressed.triggered += OnLeftButtonPressed;
        _onLeftButtonReleased.triggered += OnLeftButtonReleased;
    }

    private async void OnLeftButtonPressed(InputAction.CallbackContext context)
    {
        await Awaitable.NextFrameAsync();
        _selectionStartPosition = Input.mousePosition;
    }

    private async void OnLeftButtonReleased(InputAction.CallbackContext context)
    {
        await Awaitable.NextFrameAsync();
        _selectionEndPosition = Input.mousePosition;
        // Calculate selection box size and position
        float selectionBoxWidth = Mathf.Abs(_selectionEndPosition.x - _selectionStartPosition.x);
        float selectionBoxHeight = Mathf.Abs(_selectionEndPosition.y - _selectionStartPosition.y);
        if (selectionBoxWidth > _minSelectionBoxSize && selectionBoxHeight > _minSelectionBoxSize)
        {
            // Select units within the selection box
            var query = _entityManager.CreateEntityQuery(typeof(UnitComponent));
            var entities = query.ToEntityArray(Allocator.Temp);
            foreach (var entity in entities)
            {
                var unitComponent = _entityManager.GetComponentData<UnitComponent>(entity);
                if (IsUnitWithinSelectionBox(unitComponent.position, _selectionStartPosition, _selectionEndPosition))
                {
                    // Select the unit
                    unitComponent.isSelected = true;
                }
            }
        }
    }

    private bool IsUnitWithinSelectionBox(Vector2 unitPosition, Vector2 selectionStart, Vector2 selectionEnd)
    {
        // Calculate the selection box bounds
        float minX = Mathf.Min(selectionStart.x, selectionEnd.x);
        float maxX = Mathf.Max(selectionStart.x, selectionEnd.x);
        float minY = Mathf.Min(selectionStart.y, selectionEnd.y);
        float maxY = Mathf.Max(selectionStart.y, selectionEnd.y);
        // Check if the unit is within the selection box bounds
        return unitPosition.x >= minX && unitPosition.x <= maxX && unitPosition.y >= minY && unitPosition.y <= maxY;
    }
}
