    public float attackRange = 10f;
    public float fireballCooldown = 2f;
    public AssetReference<GameObject> fireballPrefab;
    public float fireballSpeed = 5f;

    [Header("Behavior")]
    public float keepDistance = 6f; 
    public float retreatDistance = 4f; 

    [SerializeField] private Transform player;
    [SerializeField] private Rigidbody2D rb;
    [SerializeField] private Camera mainCamera;

    private async void Start()
    {
        mainCamera = Camera.main;
        rb = GetComponent<Rigidbody2D>();
        player = GameObject.FindWithTag("Player").transform;
        await LoadFireballPrefab();
    }

    private async Task LoadFireballPrefab()
    {
        var fireball = await Addressables.LoadAssetAsync<GameObject>(fireballPrefab).Task;
    }

    private async void Update()
    {
        var distanceToPlayer = Vector2.Distance(transform.position, player.position);
        if (distanceToPlayer < keepDistance)
        {
            var direction = (player.position - transform.position).normalized;
            rb.linearVelocity = direction * moveSpeed;
        }
        else if (distanceToPlayer > retreatDistance)
        {
            var direction = (transform.position - player.position).normalized;
            rb.linearVelocity = direction * moveSpeed;
        }

        if (Vector2.Distance(transform.position, player.position) < attackRange)
        {
            await ShootFireball();
        }
    }

    private async Task ShootFireball()
    {
        var fireball = await Addressables.LoadAssetAsync<GameObject>(fireballPrefab).Task;
        var fireballInstance = Instantiate(fireball, transform.position, Quaternion.identity);
        var fireballRb = fireballInstance.GetComponent<Rigidbody2D>();
        fireballRb.linearVelocity = (player.position - transform.position).normalized * fireballSpeed;
        await Awaitable.NextFrameAsync();
    }
}
