    [SerializeField] float radius = 3;
    [SerializeField] float waitTime = 5;
    [SerializeField] float time = 0;

    Animator anim;

    Vector3 pos;

    private async void Start()
    {
        agent = GetComponent<NavMeshAgent>();

        anim = GetComponent<Animator>();

        agent.autoBraking = false;
        agent.updateRotation = false;

        await GotoNextPointAsync();
    }

    private async System.Threading.Tasks.Task GotoNextPointAsync()
    {
        agent.isStopped = false;
        float posX = Random.Range(-1 * radius, radius);

        pos = central.position + new Vector3(posX, 0, Random.Range(-1 * radius, radius));

        agent.SetDestination(pos);

        await System.Threading.Tasks.Task.Delay((int)(waitTime * 1000));

        await GotoNextPointAsync();
    }
