using UnityEngine.UI;
using UnityEngine.UIElements;
using Unity.Jobs;
using Unity.Collections;
using Unity.Burst;

public class DrawBlur : MonoBehaviour
{
    [SerializeField]
    private UIDocument topUIDocument;
    [SerializeField]
    private UIDocument topFollowUIDocument;
    [SerializeField]
    private UIDocument bottomUIDocument;
    [SerializeField]
    private UIDocument bottomFollowUIDocument;

    [SerializeField]
    private Material material;

    private Vector3[] topSample;
    private Vector3[] botSample;

    private Camera cameraCache;

    void Awake()
    {
        cameraCache = Camera.main;
    }

    async void Start()
    {
        // Load assets asynchronously
        var topAsset = await Addressables.LoadAssetAsync<GameObject>("TopAsset");
        var topFollowAsset = await Addressables.LoadAssetAsync<GameObject>("TopFollowAsset");
        var bottomAsset = await Addressables.LoadAssetAsync<GameObject>("BottomAsset");
        var bottomFollowAsset = await Addressables.LoadAssetAsync<GameObject>("BottomFollowAsset");

        // Initialize samples
        topSample = new Vector3[10];
        botSample = new Vector3[10];
    }

    void Update()
    {
        // Update samples
        for (int i = 0; i < topSample.Length; i++)
        {
            topSample[i] = topUIDocument.rootVisualElement.transform.position;
        }

        for (int i = 0; i < botSample.Length; i++)
        {
            botSample[i] = bottomUIDocument.rootVisualElement.transform.position;
        }
    }

    async void LateUpdate()
    {
        // Use awaitable to wait for the next frame
        await Awaitable.NextFrameAsync();

        // Update material
        material.SetVectorArray("TopSample", topSample);
        material.SetVectorArray("BotSample", botSample);
    }
}
