[BurstCompile]
public struct NoiseJob : IJobParallelFor
{
    public int width;
    public int height;
    public float xOrg;
    public float yOrg;
    public float scale;

    [WriteOnly]
    public NativeArray<float> results;

    public void Execute(int index)
    {
        int x = index % width;
        int y = index / width;

        float xCoord = xOrg + ((float)x / width) * scale;
        float yCoord = yOrg + ((float)y / height) * scale;

        float sample = math.cnoise(new float2(xCoord, yCoord)); // noise.snoise if you prefer
        sample = math.unlerp(-1f, 1f, sample); // Normalize -1 to 1 → 0 to 1

        results[index] = sample;
    }
}

