public class Grapple : MonoBehaviour
{
    private LineRenderer lineRenderer;
    private Vector3 grapplePoint;
    [Header("Grapple Settings")]
    public LayerMask whatIsGrappleable;
    [SerializeField] private Transform grappleTip, player;
    //To Set up with Third person view camera follow script
    [SerializeField] private Transform camera;
    public float swingSpeed = 50;
    public float originalPlayerSpeed = 5;

    [Header("Spawned Spring Settings")]
    public float maxDistance = 100f;

    [Range(0,10)]public float jointMaxDistance = .8f;
    [Range(0,10)]public float jointMinDistance = .25f;

    private float distance;
    private Rigidbody rb;

    private InputAction grappleAction;

    private void Awake()
    {
        lineRenderer = gameObject.AddComponent<LineRenderer>();
        rb = player.GetComponent<Rigidbody>();
        grappleAction = new InputAction("Grapple", binding: "<mouse>/left");
        grappleAction.triggered += ctx => GrapplePoint();
    }

    private async void GrapplePoint()
    {
        var ray = camera.GetComponent<Camera>().ScreenPointToRay(Input.mousePosition);
        if (Physics.Raycast(ray, out var hit, maxDistance, whatIsGrappleable))
        {
            grapplePoint = hit.point;
            distance = Vector3.Distance(player.position, grapplePoint);
            while (distance > jointMinDistance)
            {
                await Awaitable.NextFrameAsync();
                distance = Vector3.Distance(player.position, grapplePoint);
                rb.linearVelocity = (grapplePoint - player.position).normalized * swingSpeed;
            }
        }
    }

    private void LateUpdate()
    {
        lineRenderer.positionCount = 2;
        lineRenderer.SetPosition(0, grappleTip.position);
        lineRenderer.SetPosition(1, grapplePoint);
    }
}
