    [SerializeField] private float dropForce = 5f;
    [SerializeField] private Transform[] propellers;
    [SerializeField] private float maxPropellerSpeed = 3000f;
    [SerializeField] private Camera mainCamera;

    private Rigidbody rb;
    private InputActions inputActions;

    private async void Awake()
    {
        mainCamera = GameObject.FindWithTag("MainCamera").GetComponent<Camera>();
        rb = GetComponent<Rigidbody>();
        inputActions = new InputActions();
        inputActions.Enable();

        await Awaitable.NextFrameAsync();
    }

    private async void OnEnable()
    {
        inputActions.Player.Move.performed += ctx => MovePlayer(ctx.ReadValue<Vector2>());
        inputActions.Player.Lift.performed += ctx => ApplyLiftForce();
        inputActions.Player.Drop.performed += ctx => DropFirstAidKit();
    }

    private async void OnDisable()
    {
        inputActions.Player.Move.performed -= ctx => MovePlayer(ctx.ReadValue<Vector2>());
        inputActions.Player.Lift.performed -= ctx => ApplyLiftForce();
        inputActions.Player.Drop.performed -= ctx => DropFirstAidKit();
    }

    private void MovePlayer(Vector2 input)
    {
        rb.linearVelocity = new Vector3(input.x * moveForce, rb.linearVelocity.y, input.y * moveForce);
    }

    private void ApplyLiftForce()
    {
        rb.AddForce(Vector3.up * liftForce, ForceMode.Impulse);
    }

    private void DropFirstAidKit()
    {
        GameObject firstAidKit = Instantiate(firstAidKitPrefab, transform.position, Quaternion.identity);
        firstAidKit.GetComponent<Rigidbody>().AddForce(Vector3.down * dropForce, ForceMode.Impulse);
    }

    private async void Update()
    {
        await Awaitable.NextFrameAsync();
        float rotationInput = inputActions.Player.Rotate.ReadValue<float>();
        rb.AddTorque(Vector3.up * rotationTorque * rotationInput, ForceMode.VelocityChange);
    }
}
