    {
        [SerializeField] private NodeProgressData data;
        private CancellationTokenSource cancellationTokenSource;

        public async Task InitializeAsync()
        {
            cancellationTokenSource = new CancellationTokenSource();
            await Addressables.LoadAssetAsync<NodeProgressData>("NodeProgressData").Task;
        }

        public readonly struct TimeEnumerator : IAsyncEnumerator<float>, IAsyncEnumerable<float>
        {
            private readonly NodeProgress nodeProgress;
            private readonly CancellationToken cancellationToken;

            public TimeEnumerator(NodeProgress nodeProgress, CancellationToken cancellationToken)
            {
                this.nodeProgress = nodeProgress;
                this.cancellationToken = cancellationToken;
            }

            public readonly float Current => nodeProgress.data.currentTime;

            public async ValueTask<bool> MoveNextAsync()
            {
                await Awaitable.NextFrameAsync(cancellationToken);
                nodeProgress.data.currentTime += Time.deltaTime;
                return true;
            }

            public async ValueTask DisposeAsync()
            {
                await Task.CompletedTask;
            }

            public IAsyncEnumerator<float> GetEnumerator()
            {
                return this;
            }
        }

        public TimeEnumerator GetEnumerator(CancellationTokens cancellationToken)
        {
            return new TimeEnumerator(this, cancellationToken);
        }

        public void Dispose()
        {
            cancellationTokenSource?.Cancel();
            cancellationTokenSource?.Dispose();
        }
    }

    [System.Serializable]
    public class NodeProgressData
    {
        public float currentTime;
    }
}
