        [SerializeField] private Shatterblade sword;
        [SerializeField] private LineRenderer lines;
        [SerializeField] private Transform target;
        [SerializeField] private Vector3 offset;
        [SerializeField] private Transform rotationTarget;
        [SerializeField] private bool shouldShow;

        private Camera cameraCache;

        private async void Start()
        {
            cameraCache = Camera.main;

            var inputAction = new InputAction("Annotation");
            inputAction.AddBinding("<Mouse>/leftButton");
            inputAction.performed += ctx => ShowAnnotation(ctx.ReadValueAsButton());
            inputAction.Enable();

            await LoadAnnotationData();
        }

        private async Task LoadAnnotationData()
        {
            var annotationData = await Addressables.LoadAssetAsync<AnnotationData>("annotation_data");
            text.text = annotationData.text;
        }

