        {
            shouldShow = show;
            text.enabled = show;
            lines.enabled = show;
        }

        private void LateUpdate()
        {
            if (shouldShow)
            {
                text.transform.position = target.position + offset;
                lines.SetPosition(0, rotationTarget.position);
                lines.SetPosition(1, text.transform.position);
            }
        }
    }

