public abstract class BaseEnemy : MonoBehaviour
{
    [SerializeField] private UnitController[] unitControllers;
    [SerializeField] private LevelManager levelManager;

    protected UnitController FindNearestPlayer()
    {
        // Find the closest player unit
        UnitController nearestPlayer = null;
        float nearestDistance = Mathf.Infinity;

        foreach (UnitController unitController in levelManager.Friendlies)
        {
            float distance = Vector3.Distance(transform.position, unitController.transform.position);
            if (distance < nearestDistance)
            {
                nearestDistance = distance;
                nearestPlayer = unitController;
            }
        }

        return nearestPlayer;
    }

    public abstract Awaitable ExecuteTurn();
