using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.AddressableAssets;
using UnityEngine.InputSystem;

[RequireComponent(typeof(SpriteRenderer))]
public class AfterImage : MonoBehaviour
{
    [Tooltip("Number of sprites per distance unit.")]
    [SerializeField] private float rate = 2f;
    [SerializeField] private float lifeTime = 0.2f;

    [SerializeField] private SpriteRenderer baseRenderer;
    [SerializeField] private Camera mainCamera;

    private bool isActive = false;
    private float interval;
    private Vector3 previousPos;

    private async void Awake()
    {
        baseRenderer = GetComponent<SpriteRenderer>();
        mainCamera = await Addressables.LoadAssetAsync<Camera>("MainCamera");
    }

    private async void Update()
    {
        if (isActive)
        {
            float distance = (transform.position - previousPos).magnitude;
            interval = distance / rate;

            // Create after-image
            SpriteRenderer afterImageRenderer = await Addressables.LoadAssetAsync<SpriteRenderer>("AfterImageSprite");
            afterImageRenderer.transform.position = previousPos;
            afterImageRenderer.transform.rotation = baseRenderer.transform.rotation;
            afterImageRenderer.sprite = baseRenderer.sprite;

            // Fade out after-image
            await FadeOutAfterImage(afterImageRenderer);

            previousPos = transform.position;
        }
    }

    private async System.Threading.Tasks.Task FadeOutAfterImage(SpriteRenderer afterImageRenderer)
    {
        float timer = 0f;
        while (timer < lifeTime)
        {
            afterImageRenderer.color = new Color(1f, 1f, 1f, 1f - timer / lifeTime);
            await System.Threading.Tasks.Task.Delay(16); // 16ms = 60fps
            timer += 0.016f;
        }
        Object.Destroy(afterImageRenderer.gameObject);
    }

    public void OnMove(InputAction.CallbackContext context)
    {
        if (context.performed)
        {
            isActive = true;
        }
        else if (context.canceled)
        {
            isActive = false;
        }
    }
}
