using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Addressables;

public class CameraScript : MonoBehaviour
{
    [SerializeField]
    private Renderer bottomLeftRenderer, topRightRenderer;
    private float zoomingSpeed;
    private Camera thisCam;

    private async void Start()
    {
        thisCam = GetComponent<Camera>();
        zoomingSpeed = ((float)MazeProperties.MazeWidth + (float)MazeProperties.MazeHeight) / 100f;
        await ZoomOut();
    }

    private async System.Threading.Tasks.Task ZoomOut()
    {
        while (true)
        {
            if (IsVisible(bottomLeftRenderer) && IsVisible(topRightRenderer))
                break;
            thisCam.orthographicSize += zoomingSpeed * Time.deltaTime;
            await System.Threading.Tasks.Task.Yield();
        }
    }

    private bool IsVisible(Renderer renderer)
    {
        Plane[] planes = GeometryUtility.CalculateFrustumPlanes(thisCam);
        return GeometryUtility.TestPlanesAABB(planes, renderer.bounds);
    }
}

