    public class UnderWaterManager : HigSingleInstance<UnderWaterManager>
    {
        public enum RenderType
        {
            RenderPipelineManager,
            RenderFeature
        }
        public RenderType renderType = RenderType.RenderPipelineManager;
        public float underWaterViewDistance = 100f;
        public Color underWaterColor = Color.cyan;
        public float underWaterPow = 1f;
        public Gradient depthColorGradient;
        public float depthColorDistance = 100f;
        public float depthColorFactor = 1f;
        public Color underWaterLightColor = Color.white;

        private Camera _camera;
        private RenderFeature _renderFeature;

        private void Awake()
        {
            _camera = Camera.main;
            _renderFeature = new UnderWaterRenderFeature();
        }

        private void OnRenderImage(RenderTexture source, RenderTexture destination)
        {
            if (renderType == RenderType.RenderFeature)
            {
                _renderFeature.Render(_camera, source, destination);
            }
            else
            {
                Graphics.Blit(source, destination);
            }
        }
    }

    public class UnderWaterRenderFeature : ScriptableRenderFeature
    {
        public override void Create()
        {
        }

        public override void AddRenderPasses(ScriptableRenderer renderer, ref RenderingData renderingData)
        {
            var renderPass = new UnderWaterRenderPass();
            renderer.EnqueueRenderPass(renderPass, RenderPassEvent.BeforeRenderTransparency);
        }
    }

    public class UnderWaterRenderPass : ScriptableRenderPass
    {
        public UnderWaterRenderPass()
        {
        }

        public override void Execute(ScriptableRenderContext context, ref RenderingData renderingData)
        {
            var camera = renderingData.cameraData.camera;
            var source = renderingData.cameraData.targetTexture;
            var destination = renderingData.cameraData.targetTexture;

            // Apply underwater effect
            var underWaterManager = UnderWaterManager.Instance;
            var underWaterColor = underWaterManager.underWaterColor;
            var underWaterPow = underWaterManager.underWaterPow;
            var depthColorGradient = underWaterManager.depthColorGradient;
            var depthColorDistance = underWaterManager.depthColorDistance;
            var depthColorFactor = underWaterManager.depthColorFactor;
            var underWaterLightColor = underWaterManager.underWaterLightColor;

            // Render underwater effect
            var renderTexture = RenderTexture.GetTemporary(source.width, source.height, 0, RenderTextureFormat.ARGB32);
            Graphics.Blit(source, renderTexture, new Material(Shader.Find("Custom/UnderWaterShader")));
            Graphics.Blit(renderTexture, destination);
            RenderTexture.ReleaseTemporary(renderTexture);
        }
    }
}
