using Unity.Physics;
using Unity.Physics.Extensions;
using Unity.Physics.Systems;
using Unity.Entities;
using UnityEngine;
using RaycastHit = Unity.Physics.RaycastHit;
using UnityEngine.InputSystem;

namespace CameraSmoothTrack
{
    public class CameraSmoothTrack : MonoBehaviour
    {
        public GameObject Target;
        public GameObject LookTo;
        [Range(0, 1)] public float LookToInterpolateFactor = 0.9f;

        public GameObject LookFrom;
        [Range(0, 1)] public float LookFromInterpolateFactor = 0.9f;

        private Vector3 oldPositionTo;
        private Camera _camera;

        private async void Start()
        {
            _camera = Camera.main;
            oldPositionTo = (transform.position + Vector3.forward);
            while (true)
            {
                await Awaitable.NextFrameAsync();
                TrackTarget();
            }
        }

        private void TrackTarget()
        {
            if (Target != null)
            {
                var targetPosition = Target.transform.position;
                var lookToPosition = LookTo.transform.position;
                var lookFromPosition = LookFrom.transform.position;

                var lookToDirection = (lookToPosition - transform.position).normalized;
                var lookFromDirection = (lookFromPosition - transform.position).normalized;

                var lookToAngle = Vector3.Angle(lookToDirection, transform.forward);
                var lookFromAngle = Vector3.Angle(lookFromDirection, transform.forward);

                var lookToInterpolatedAngle = Mathf.Lerp(lookToAngle, 0, LookToInterpolateFactor);
                var lookFromInterpolatedAngle = Mathf.Lerp(lookFromAngle, 0, LookFromInterpolateFactor);

                transform.rotation = Quaternion.Slerp(transform.rotation, Quaternion.LookRotation(lookToDirection), lookToInterpolatedAngle * Time.deltaTime);
                transform.rotation = Quaternion.Slerp(transform.rotation, Quaternion.LookRotation(lookFromDirection), lookFromInterpolatedAngle * Time.deltaTime);
            }
        }
    }
}
