    [SerializeField] private float motorForce;
    [SerializeField] private float breakForce;
    [SerializeField] private float maxSteerAngle;

    [SerializeField] private WheelCollider frontLeftWheelCollider;
    [SerializeField] private WheelCollider frontRightWheelCollider;
    [SerializeField] private WheelCollider rearLeftWheelCollider;
    [SerializeField] private WheelCollider rearRightWheelCollider;

    [SerializeField] private InputActionAsset inputAsset;

    private Rigidbody rb;
    private float horizontalInput;
    private float verticalInput;
    private float currentSteerAngle;
    private float currentBreakForce;
    private bool isBreaking;

    private void Awake()
    {
        rb = GetComponent<Rigidbody>();
        inputAsset = Addressables.LoadAssetAsync<InputActionAsset>("inputactions").Result;
    }

    private void OnEnable()
    {
        inputAsset.FindActionMap("Car").FindAction("Horizontal").performed += ctx => horizontalInput = ctx.ReadValue<float>();
        inputAsset.FindActionMap("Car").FindAction("Vertical").performed += ctx => verticalInput = ctx.ReadValue<float>();
        inputAsset.FindActionMap("Car").FindAction("Break").performed += ctx => isBreaking = ctx.ReadValue<float>() > 0;
    }

    private void FixedUpdate()
    {
        currentSteerAngle = maxSteerAngle * horizontalInput;
        currentBreakForce = isBreaking ? breakForce : 0;

        frontLeftWheelCollider.steerAngle = currentSteerAngle;
        frontRightWheelCollider.steerAngle = currentSteerAngle;

        rearLeftWheelCollider.motorTorque = motorForce * verticalInput;
        rearRightWheelCollider.motorTorque = motorForce * verticalInput;

        frontLeftWheelCollider.brakeTorque = currentBreakForce;
        frontRightWheelCollider.brakeTorque = currentBreakForce;
        rearLeftWheelCollider.brakeTorque = currentBreakForce;
        rearRightWheelCollider.brakeTorque = currentBreakForce;

        rb.linearVelocity = new Vector3(x: horizontalInput * motorForce, y: rb.linearVelocity.y, z: verticalInput * motorForce);
    }
