using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Jobs;
using Unity.Mathematics;
using Unity.Jobs;
using Unity.Collections;
using Unity.Burst;
using UnityEngine.InputSystem;

public class JobsTesting : MonoBehaviour
{
    [SerializeField] private bool useJobs;
    [SerializeField] private Transform entity;
    [SerializeField] private int numOfEntities;
    private List<Entity> entities = new List<Entity>();
    private Camera mainCamera;

    public class Entity
    {
        public Transform transform;
        public float moveY;
    }

    private void Awake()
    {
        mainCamera = Camera.main;
    }

    private void Start()
    {
        for (int i = 0; i < numOfEntities; i++)
        {
            Transform entityTransform = Instantiate(entity, new Vector3(UnityEngine.Random.Range(-8f, 8f), UnityEngine.Random.Range(-5f, 5f)), Quaternion.identity);
            entityTransform.gameObject.GetComponent<SpriteRenderer>();
            entities.Add(new Entity { transform = entityTransform, moveY = 0f });
        }
    }

    private void Update()
    {
        if (useJobs)
        {
            var entityMoves = new EntityMoveJob { entities = entities.ToArray() };
            var handle = entityMoves.Schedule(entities.Count, 1);
            handle.Complete();
        }
        else
        {
            foreach (var entity in entities)
            {
                entity.transform.position += new Vector3(0, entity.moveY * Time.deltaTime, 0);
            }
        }
    }

    [BurstCompile]
    public struct EntityMoveJob : IJobParallelFor
    {
        public Entity[] entities;

        public void Execute(int index)
        {
            entities[index].transform.position += new Vector3(0, entities[index].moveY * Time.deltaTime, 0);
        }
    }
}
```

