        if (Physics.Raycast(transform.position, fwd, out hit))
        {
            SpawnExplosion(hit.point, hit.transform);
            return hit.point;
        }
        else
        {
            return transform.position + fwd;
        }
    }

    private void Update()
    {
        if (canFire)
        {
            lr.enabled = true;
            lr.SetPosition(0, transform.position);
            lr.SetPosition(1, CastRay());
            canFire = false;
            Invoke(nameof(DisableLaser), laserOffTime);
        }
    }

    private void DisableLaser()
    {
        lr.enabled = false;
        canFire = true;
    }

