public class UI_Drag : MonoBehaviour
{
    [SerializeField] private UIDocument uiDocument;
    [SerializeField] private VisualElement dragElement;

    private Vector3 mousePosition;
    private Vector3 previousMousePosition;

    private void Awake()
    {
        var clickAction = new InputAction("Click", binding: "<Mouse>/leftButton");
        clickAction.performed += OnClickPerformed;
        clickAction.Enable();

        var dragAction = new InputAction("Drag", binding: "<Mouse>/delta");
        dragAction.performed += OnDragPerformed;
        dragAction.Enable();
    }

    private async void OnClickPerformed(InputAction.CallbackContext ctx)
    {
        if (ctx.performed)
        {
            var mousePosition = Mouse.current.position.ReadValue();
            var raycast = uiDocument.rootVisualElement.WorldToLocal(mousePosition);
            if (dragElement.WorldBounds.Contains(raycast))
            {
                await DragElement();
            }
        }
    }

    private async System.Threading.Tasks.Task DragElement()
    {
        while (Mouse.current.leftButton.isPressed)
        {
            var mousePosition = Mouse.current.position.ReadValue();
            var raycast = uiDocument.rootVisualElement.WorldToLocal(mousePosition);
            dragElement.transform.position = raycast;
            await System.Threading.Tasks.Task.Yield();
        }
    }

    private void OnDragPerformed(InputAction.CallbackContext ctx)
    {
        if (ctx.performed)
        {
            var mousePosition = Mouse.current.position.ReadValue();
            var raycast = uiDocument.rootVisualElement.WorldToLocal(mousePosition);
            dragElement.transform.position = raycast;
        }
    }
