public class RockThrower : MonoBehaviour
{
    [Header("Projectile Settings")]
    [SerializeField] private GameObject rockPrefab;
    [SerializeField] private Transform throwOrigin; // hand
    [SerializeField] private float throwForce = 100f;

    [Header("Inventory")]
    [SerializeField] private int currentRocks = 10;
    [SerializeField] private int maxRocks = 50;
    [SerializeField] private float pickupRange = 3f;
    [SerializeField] private LayerMask pickupLayerMask; // Assign in Inspector to only hit "RockPickup" layer

    [Header("References")]
    [SerializeField] private Camera playerCamera;

    private InputAction throwRockAction;

    private void Awake()
    {
        throwRockAction = new InputAction("ThrowRock", binding: "<Mouse>/leftButton");
        throwRockAction.performed += ThrowRock;
    }

    private async Awaitable ThrowRock(InputAction.CallbackContext context)
    {
        if (currentRocks > 0)
        {
            var rock = Instantiate(rockPrefab, throwOrigin.position, throwOrigin.rotation);
            var rb = rock.GetComponent<Rigidbody>();
            rb.linearVelocity = throwOrigin.forward * throwForce;
            currentRocks--;
        }
    }

    private async Awaitable PickupRock()
    {
        var colliders = Physics.OverlapSphere(transform.position, pickupRange, pickupLayerMask);
        foreach (var collider in colliders)
        {
            var rock = collider.GetComponent<Rock>();
            if (rock != null)
            {
                Destroy(rock.gameObject);
                currentRocks = Mathf.Min(currentRocks + 1, maxRocks);
                break;
            }
        }
    }
}
