using UnityEngine;
using UnityEngine.UI;
using UnityEngine.UIElements;
using UnityEngine.InputSystem;

[RequireComponent(typeof(UIDocument))]
public class UIFader : MonoBehaviour
{
    [SerializeField] float fadeSpeed = 10f;
    [SerializeField] UIDocument uiDocument;
    [SerializeField] bool startVisible;
    [SerializeField] bool startWithFade;

    private VisualElement groupToFade;
    private Camera cameraCache;

    private void Awake()
    {
        cameraCache = Camera.main;
        groupToFade = uiDocument.rootVisualElement;
    }

    async void Start()
    {
        if (startWithFade)
        {
            await FadeIn();
        }
        else if (!startVisible)
        {
            await FadeOut();
        }
    }

    async void Update()
    {
        if (InputAction.ReadValue<float>("ToggleUI") > 0.5f)
        {
            if (groupToFade.enabledSelf)
            {
                await FadeOut();
            }
            else
            {
                await FadeIn();
            }
        }
        await Awaitable.NextFrameAsync();
    }

    async System.Threading.Tasks.Task FadeIn()
    {
        groupToFade.enabled = true;
        float elapsedTime = 0;
        while (elapsedTime < 1f)
        {
            groupToFade.style.opacity = elapsedTime;
            elapsedTime += fadeSpeed * Time.deltaTime;
            await Awaitable.NextFrameAsync();
        }
        groupToFade.style.opacity = 1f;
    }

    async System.Threading.Tasks.Task FadeOut()
    {
        float elapsedTime = 0;
        while (elapsedTime < 1f)
        {
            groupToFade.style.opacity = 1f - elapsedTime;
            elapsedTime += fadeSpeed * Time.deltaTime;
            await Awaitable.NextFrameAsync();
        }
        groupToFade.style.opacity = 0f;
        groupToFade.enabled = false;
    }
}

