    {
        manager = World.DefaultGameObjectInjectionWorld.EntityManager;
        buildPhysicsWorld = World.DefaultGameObjectInjectionWorld.GetOrCreateSystem<BuildPhysicsWorld>();
        stepPhysicsWorld = World.DefaultGameObjectInjectionWorld.GetOrCreateSystem<StepPhysicsWorld>();
    }

    public struct RaycastJob : IJob
    {
        public RaycastInput Raycast
        {
            get;
            set;
        }

        public NativeList<Unity.Physics.RaycastHit> Hits
        {
            get;
            set;
        }
    }

    private async void Start()
    {
        await Awaitable.NextFrameAsync();
        _hits = new NativeList<Unity.Physics.RaycastHit>(Allocator.Persistent);
        raycastInput = new RaycastInput
        {
            Start = transform.position,
            End = transform.position + direction * distance,
            Filter = new CollisionFilter
            {
                BelongsTo = ~0u,
                CollidesWith = ~0u,
                GroupIndex = 0
            }
        };
        var raycastJob = new RaycastJob
        {
            Raycast = raycastInput,
            Hits = _hits
        };
        raycastJob.Schedule().Complete();
    }

    private void OnDestroy()
    {
        if (_hits.IsCreated)
        {
            _hits.Dispose();
        }
    }
