    [SerializeField] private float normalJumpHeight;
    [SerializeField] private float sprintJumpHeight;
    [SerializeField] private float jumpHeight = 1.47f;
    [SerializeField] private float groundDistance = 1f;
    [Space]
    [SerializeField] private bool isSprinting = false;
    [SerializeField] private bool isGrounded;
    [Space]
    [SerializeField] private LayerMask groundMask;
    [SerializeField] private Camera playerCamera;
    private Vector3 velocity;
    private Rigidbody rb;
    private InputAction moveAction;
    private InputAction jumpAction;
    private InputAction sprintAction;

    private async void Awake()
    {
        rb = player.GetComponent<Rigidbody>();
        moveAction = new InputAction("Move", binding: "<Gamepad>/leftStick");
        jumpAction = new InputAction("Jump", binding: "<Gamepad>/a");
        sprintAction = new InputAction("Sprint", binding: "<Gamepad>/x");
        moveAction.Enable();
        jumpAction.Enable();
        sprintAction.Enable();
        playerCamera = playerCameraT.GetComponent<Camera>();
    }

    private async void Update()
    {
        var moveValue = moveAction.ReadValue<Vector2>();
        var jumpValue = jumpAction.triggered;
        var sprintValue = sprintAction.triggered;

        if (isGrounded)
        {
            rb.linearVelocity = new Vector3(moveValue.x * speed, rb.linearVelocity.y, moveValue.y * speed);
            if (jumpValue)
            {
                rb.linearVelocity = new Vector3(rb.linearVelocity.x, jumpHeight, rb.linearVelocity.z);
            }
            if (sprintValue)
            {
                isSprinting = true;
                speed = sprintJumpHeight;
            }
            else
            {
                isSprinting = false;
                speed = normalJumpHeight;
            }
        }
        else
        {
            rb.linearVelocity = new Vector3(rb.linearVelocity.x, rb.linearVelocity.y - gravity * Time.deltaTime, rb.linearVelocity.z);
        }

        await Awaitable.NextFrameAsync();
    }
}
