    [SerializeField] private float scoreThreshold = 0.5f;
    [SerializeField] private bool useWebcam = false;

    private const int k_NumAnchors = 896;
    private float[,] m_Anchors;

    private const int k_NumKeypoints = 6;
    private const int detectorInputSize = 128;

    private Worker m_FaceDetectorWorker;
    private Tensor<float> m_DetectorInput;
    private Awaitable m_DetectAwaitable;

    private float m_TextureWidth;
    private float m_TextureHeight;

    private WebCamTexture webcamTexture;
    [SerializeField] private HoloLens2DA holoLens2DA;
    private Texture currentTexture;

    private async void Start()
    {
        // Initialize face detection system
        await InitializeFaceDetection();
    }

    private async Awaitable InitializeFaceDetection()
    {
        // Load face detector model and anchors
        faceDetector = await Addressables.LoadAssetAsync<ModelAsset>("FaceDetectorModel");
        m_Anchors = await LoadAnchors(anchorsCSV);

        // Initialize face detector worker
        m_FaceDetectorWorker = new Worker(faceDetector);

        // Initialize detector input tensor
        m_DetectorInput = new Tensor<float>(detectorInputSize, detectorInputSize, 3);

        // Initialize detect awaitable
        m_DetectAwaitable = m_FaceDetectorWorker.Detect(m_DetectorInput);
    }

    private float[,] LoadAnchors(TextAsset anchorsCSV)
    {
        // Load anchors from CSV file
        string[] anchorsData = anchorsCSV.text.Split(',');
        float[,] anchors = new float[k_NumAnchors, 4];

        for (int i = 0; i < k_NumAnchors; i++)
        {
            anchors[i, 0] = float.Parse(anchorsData[i * 4]);
            anchors[i, 1] = float.Parse(anchorsData[i * 4 + 1]);
            anchors[i, 2] = float.Parse(anchorsData[i * 4 + 2]);
            anchors[i, 3] = float.Parse(anchorsData[i * 4 + 3]);
        }

        return anchors;
    }
