public class Player : MonoBehaviour, IKitchenObjectParent
{
    [SerializeField] private float moveSpeed = 7f;
    [SerializeField] private GameInput gameInput;
    [SerializeField] private LayerMask countersLayerMask;
    [SerializeField] private Transform kitchenObjectHoldPoint;

    private bool isWalking;
    private Vector3 lastInteractDir;
    private BaseCounter selectedCounter;
    private KitchenObject kitchenObject;
    private Rigidbody rb;

    private Camera mainCamera;

    private async void Awake()
    {
        // Cache main camera
        mainCamera = GameObject.FindWithTag("MainCamera").GetComponent<Camera>();

        // Cache rigidbody
        rb = GetComponent<Rigidbody>();
    }

    private async void OnMove(InputAction.CallbackContext context)
    {
        // Get move input value
        Vector2 moveInput = context.ReadValue<Vector2>();

        // Calculate move direction
        Vector3 moveDir = new Vector3(moveInput.x, 0, moveInput.y);

        // Normalize move direction
        moveDir = moveDir.normalized;

        // Apply move direction to rigidbody
        rb.linearVelocity = moveDir * moveSpeed;
    }

    private async void OnInteract(InputAction.CallbackContext context)
    {
        // Check if interact action was triggered
        if (context.triggered)
        {
            // Raycast from camera to detect interactable objects
            Ray ray = mainCamera.ScreenPointToRay(Input.mousePosition);
            RaycastHit hit;

            if (Physics.Raycast(ray, out hit, 10f, countersLayerMask))
            {
                // Get interacted object
                BaseCounter interactedObject = hit.transform.GetComponent<BaseCounter>();

                // Select interacted object
                SelectCounter(interactedObject);
            }
        }
    }

    private void SelectCounter(BaseCounter counter)
    {
        // Deselect previous counter
        if (selectedCounter != null)
        {
            selectedCounter.OnDeselect();
        }

        // Select new counter
        selectedCounter = counter;
        selectedCounter.OnSelect();

        // Invoke OnSelectedCounterChanged event
        OnSelectedCounterChanged?.Invoke(this, new OnSelectedCounterChangedEventArgs(selectedCounter));
    }

    public event EventHandler OnPickedSomething;
    public event EventHandler<OnSelectedCounterChangedEventArgs> OnSelectedCounterChanged;

    public class OnSelectedCounterChangedEventArgs : EventArgs
    {
        public BaseCounter selectedCounter;
    }
}
