public class LargeStructJobs : MonoBehaviour
{
    [BurstCompile]
    public struct SetNew : IJobParallelFor
    {
        [WriteOnly] public NativeArray<LargeStruct> largeStructs;

        public void Execute(int i)
        {
            largeStructs[i] = new LargeStruct();
        }
    }

    [BurstCompile]
    public void Update()
    {
        // Create a new NativeArray and schedule the job
        var largeStructs = new NativeArray<LargeStruct>(10, Allocator.TempJob);
        var job = new SetNew { largeStructs = largeStructs };
        JobHandle handle = job.Schedule(largeStructs.Length, 1);
        handle.Complete();
        largeStructs.Dispose();
    }
}

