    {
        if (InputAction.FindActionMap("UI").FindAction("Click").triggered)
        {
            Vector2 mousePosition = InputAction.FindActionMap("UI").FindAction("Click").ReadValue<Vector2>();
            if (dragging)
            {
                endPoint = mousePosition;
