            else
            {
                startPoint = mousePosition;
                _lastClickTime = Time.time;
            }
        }

        if (InputAction.FindActionMap("UI").FindAction("RightClick").triggered)
        {
            rightClick = InputAction.FindActionMap("UI").FindAction("RightClick").ReadValue<Vector2>();
