        {
            doubleClick = InputAction.FindActionMap("UI").FindAction("DoubleClick").ReadValue<Vector2>();
        }

        await Awaitable.NextFrameAsync();
    }

    private void LateUpdate()
    {
        // Update selection rectangle
        if (dragging)
        {
            square.sizeDelta = new Vector2(Mathf.Abs(endPoint.x - startPoint.x), Mathf.Abs(endPoint.y - startPoint.y));
            square.pivot = new Vector2(0.5f, 0.5f);
            square.anchoredPosition = new Vector2((startPoint.x + endPoint.x) / 2, (startPoint.y + endPoint.y) / 2);
