using System;
using System.Collections;
using System.Collections.Generic;
using Unity.Burst;
using Unity.Collections;
using Unity.Jobs;
using UnityEngine;

public class ArrayReplace : MonoBehaviour
{
    [SerializeField] private int fieldSize;
    private NativeArray<Vector2> field;

    private enum ScrollDir
    {
        Up,
        Down,
        Left,
        Right
    }

    private async UniTaskVoid Start()
    {
        field = new NativeArray<Vector2>(fieldSize * fieldSize, Allocator.Persistent);
        await UniTask.NextFrameAsync();
    }

    private async UniTaskVoid Move(ScrollDir dir)
    {
        await UniTask.NextFrameAsync();
        switch (dir)
        {
            case ScrollDir.Up:
                for (int i = 1; i < fieldSize; i++)
                {
                    for (int j = 0; j < fieldSize; j++)
                    {
                        var currentIndex = i * fieldSize + j;
                        var previousIndex = (i - 1) * fieldSize + j;
                        field[currentIndex] = field[previousIndex];
                    }
                }
                break;
            case ScrollDir.Down:
                for (int i = fieldSize - 2; i >= 0; i--)
                {
                    for (int j = 0; j < fieldSize; j++)
                    {
                        var currentIndex = i * fieldSize + j;
                        var nextIndex = (i + 1) * fieldSize + j;
                        field[currentIndex] = field[nextIndex];
                    }
                }
                break;
            case ScrollDir.Left:
                for (int i = 0; i < fieldSize; i++)
                {
                    for (int j = 1; j < fieldSize; j++)
                    {
                        var currentIndex = i * fieldSize + j;
                        var previousIndex = i * fieldSize + (j - 1);
                        field[currentIndex] = field[previousIndex];
                    }
                }
                break;
            case ScrollDir.Right:
                for (int i = 0; i < fieldSize; i++)
                {
                    for (int j = fieldSize - 2; j >= 0; j--)
                    {
                        var currentIndex = i * fieldSize + j;
                        var nextIndex = i * fieldSize + (j + 1);
                        field[currentIndex] = field[nextIndex];
                    }
                }
                break;
        }
        await UniTask.NextFrameAsync();
    }

    private async UniTaskVoid OnDestroy()
    {
        await UniTask.NextFrameAsync();
        field.Dispose();
    }
}
