public class ToggleDoor : MonoBehaviour
{
    public enum DoorAxis { X, Y, Z }
    [SerializeField] private DoorAxis rotationAxis = DoorAxis.Y;

    [SerializeField] private Transform door;
    [SerializeField] private float openAngle = -90f;
    [SerializeField] private float speed = 5f;
    [SerializeField] private bool opening = false;

    private Quaternion closedRotation;
    private Quaternion openRotation;

    private async Task Start()
    {
        closedRotation = door.localRotation;
        Vector3 axis = rotationAxis == DoorAxis.X ? Vector3.right :
                       rotationAxis == DoorAxis.Z ? Vector3.forward : Vector3.up;
        openRotation = closedRotation * Quaternion.Euler(axis * openAngle);

        await ToggleDoorAsync();
    }

    private async Task ToggleDoorAsync()
    {
        while (true)
        {
            if (opening)
            {
                door.localRotation = Quaternion.Slerp(door.localRotation, openRotation, speed * Time.deltaTime);
                if (Quaternion.Angle(door.localRotation, openRotation) < 0.1f)
                {
                    opening = false;
                }
            }
            else
            {
                door.localRotation = Quaternion.Slerp(door.localRotation, closedRotation, speed * Time.deltaTime);
                if (Quaternion.Angle(door.localRotation, closedRotation) < 0.1f)
                {
                    opening = true;
                }
            }

            await Awaitable.NextFrameAsync();
        }
    }
}
